      <div class="phone-music-side-apps">
       ${_renderHomeIcon({ id: 'reading', icon: 'reading', name: (_shopMeta?.reading?.name || '阅读') })}
       ${_renderHomeIcon({ id: '__locked4__', icon: 'locked', name: '待解锁' })}
     </div>
