      tv:      `<svg ${common}><rect x="2" y="7" width="20" height="13" rx="2"/><path d="m17 2-5 5-5-5"/></svg>`,
      dining:  `<svg ${common}><path d="M3 11h18l-1 9H4l-1-9Z"/><path d="M5 11V8a7 7 0 0 1 14 0v3"/></svg>`,
