  // 把生成后的正文写回持久化（当前期 histIdx<0 写 program._body；历史期写 history[histIdx].body）
  async function _radioPersistBody(catId, idx, histIdx, newBody) {
    try {
      const pd = await _getPhoneData();
      const programs = (pd.radioPrograms && pd.radioPrograms[catId]) || [];
      const prog = programs[idx];
      if (!prog) return;
      if (typeof histIdx === 'number' && histIdx >= 0 && Array.isArray(prog.history) && prog.history[histIdx]) {
        prog.history[histIdx].body = newBody;
      } else {
        prog._body = newBody;
        // 当前期：提取正文里 AI 输出的下期预告元数据 [[next:名|简介]]，存进 nextShow/nextPreview 供续期用
        try {
          const nx = _radioExtractNext(newBody);
          if (nx) {
            if (nx.name) prog.nextShow = nx.name;
            if (nx.desc) prog.nextPreview = nx.desc;
          }
        } catch (_) {}
      }
      await _savePhoneData(pd);
    } catch (e) { console.warn('[电台正文持久化]', e); }
  }

  // 玩法分发器：按玩法 handler 调用对应处理函数（参与玩法的统一入口）
  async function _radioHandlePlay(play, overlay, prog, ctx, resumeFn, opts) {
    const handler = play && play.handler;
    if (handler === 'mail') {
      return _radioHandleMailInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    if (handler === 'vote') {
      return _radioHandleVoteInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    if (handler === 'request') {
      return _radioHandleSongInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    if (handler === 'call') {
      return _radioHandleCallInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    if (handler === 'lottery') {
      return _radioHandleLotteryInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    if (handler === 'divination') {
      return _radioHandleDivinationInteract(play, overlay, prog, ctx, resumeFn, opts);
    }
    // 未知玩法兜底
    UI.showToast('该玩法暂未开放', 1500);
  }

  // 互动暂停 → 处理留言玩法：弹窗收集 → 生成 → 替换锚点 → 重渲染 → 从锚点后续播
  // opts.skip=true 时为"不留言"路径：跳过弹窗，mail 传 null（生成纯虚拟听众读留言 + 收尾）
  async function _radioHandleMailInteract(play, overlay, prog, ctx, resumeFn, opts) {
    const isSkip = !!(opts && opts.skip);
    let mail = null;
    if (!isSkip) {
      mail = await _radioMailInput();
      if (!mail) return;  // 取消：保持暂停态，两个按钮还在
    }
    // 锁定卡片按钮，显示生成中
    const card = overlay.querySelector(`.phone-radio-detail-body .phone-radio-interact[data-seg-idx]`);
    const actions = card ? card.querySelector('.phone-radio-interact-actions') : null;
    const allBtns = card ? card.querySelectorAll('.phone-radio-interact-btn') : [];
    const descEl = card ? card.querySelector('.phone-radio-interact-desc') : null;
    allBtns.forEach(b => { b.disabled = true; });
    if (descEl) descEl.textContent = isSkip ? '主播正在读留言…' : '主播正在挑选留言…';
    UI.showToast(isSkip ? '主播正在读留言…' : '主播正在挑选留言…', 1500);

    // 锚点前的已播正文（喂给生成函数当作"前半段"）
    const anchor0 = (play && play.anchor) || '读留言';
    const body0 = prog._body || _RADIO_FAKE_BODY;
    const anchorRe0 = new RegExp('^\\s*\\[\\[\\s*' + anchor0.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*\\]\\]\\s*$', 'm');
    const priorBody = body0.split(anchorRe0)[0] || '';

    const segment = await _radioGenMailSegment(prog, mail, priorBody);
    if (!segment) {
      UI.showToast('生成失败，请重试', 1800);
      allBtns.forEach(b => { b.disabled = false; });
      if (descEl) descEl.textContent = (play && play.descPending) || '主播在等你的留言，要不要参与？';
      return;
    }
    // 把生成的留言段替换掉正文里的 [[读留言]] 锚点（标记为 done + 保留留言正文）
    const anchor = anchor0;
    const body = body0;
    const anchorRe = anchorRe0;
    const newBody = body.replace(anchorRe, `[[${anchor}:done]]\n${segment}`);
    prog._body = newBody;
    // 同步主线：记下本期玩家的互动摘要
    prog._lastInteract = (mail && (mail.content || '').trim())
      ? `给节目发了留言${mail.region ? `（来自${mail.region}）` : ''}：${(mail.content || '').trim().slice(0, 60)}`
      : '没有留言，听主播读了别的听众来信';
    // 续播交给 resumeFn 处理
    if (typeof resumeFn === 'function') resumeFn(newBody);
  }

  // ===== 抽奖玩法 =====
  // 弹窗：输入姓名参与抽奖
  // 返回 null（取消）或 { name: '参与者姓名' }
  function _radioLotteryInput(prizeName) {
    return new Promise((resolve) => {
      const defName = _radioPlayerName();
      const mask = document.createElement('div');
      mask.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;padding:20px';
      mask.innerHTML = `
        <div style="background:var(--bg);border:1px solid var(--border);border-radius:14px;padding:20px;max-width:360px;width:100%;color:var(--text)">
          <div style="font-size:15px;font-weight:600;margin-bottom:4px">🎁 参与抽奖</div>
          <div style="font-size:12px;color:var(--text-secondary);margin-bottom:16px">奖品：${Utils.escapeHtml(prizeName || '神秘礼物')}</div>
          
          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">你的名字</label>
          <input id="radio-lottery-name" type="text" maxlength="16" value="${Utils.escapeHtml(defName)}" placeholder="留下你的名字" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:16px">
          
          <div style="display:flex;gap:10px">
            <button id="radio-lottery-cancel" style="flex:1;padding:10px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;cursor:pointer">取消</button>
            <button id="radio-lottery-ok" style="flex:1;padding:10px;font-size:14px;background:var(--accent);color:#fff;border:none;border-radius:10px;cursor:pointer">确定</button>
          </div>
        </div>`;
      document.body.appendChild(mask);
      const close = (data) => { try { mask.remove(); } catch (_) {} resolve(data); };
      mask.querySelector('#radio-lottery-cancel').onclick = () => close(null);
      // 点遮罩空白处关闭：要求按下和抬起都落在 mask 本身，避免输入框失焦/软键盘收起/点按钮时误触关闭
      let _maskDownOnSelf = false;
      mask.addEventListener('mousedown', (e) => { _maskDownOnSelf = (e.target === mask); });
      mask.addEventListener('click', (e) => { if (e.target === mask && _maskDownOnSelf) close(null); _maskDownOnSelf = false; });
      mask.querySelector('#radio-lottery-ok').onclick = () => {
        const name = (mask.querySelector('#radio-lottery-name')?.value || '').trim();
        if (!name) { UI.showToast('请留下你的名字', 1500); return; }
        close({ name });
      };
      setTimeout(() => { try { mask.querySelector('#radio-lottery-name')?.focus(); } catch(_) {} }, 100);
    });
  }

  // ===== 问卜玩法 =====
  // 弹窗：填写问卜信息（名字 + 所问 + 额外信息）。返回 null（取消）或 { name, question, extra }
  // "所问"必填；名字默认取玩家署名、可空（空则匿名）；额外信息（生辰/数字/补充）可空。
  function _radioDivinationInput() {
    return new Promise((resolve) => {
      const defName = _radioPlayerName();
      const mask = document.createElement('div');
      mask.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;padding:20px';
      mask.innerHTML = `
        <div style="background:var(--bg);border:1px solid var(--border);border-radius:14px;padding:20px;max-width:360px;width:100%;color:var(--text);max-height:84vh;overflow-y:auto">
          <div style="font-size:15px;font-weight:600;margin-bottom:4px">${_radioDivinationSvg()}向主播问卜</div>
          <div style="font-size:12px;color:var(--text-secondary);margin-bottom:16px">把心中的困惑递上来，主播会为你卜上一卦</div>

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">署名（可空）</label>
          <input id="radio-div-name" type="text" maxlength="16" value="${Utils.escapeHtml(defName)}" placeholder="你的称呼，留空则匿名" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:12px">

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">想问什么</label>
          <textarea id="radio-div-question" maxlength="200" rows="3" placeholder="例如：最近的事业、一段感情、要不要做某个决定…" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;resize:none;margin-bottom:12px"></textarea>

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">额外信息（可空）</label>
          <textarea id="radio-div-extra" maxlength="200" rows="2" placeholder="主播若用得上的信息：生辰、心里想的一个数字、抽到的牌号等" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;resize:none;margin-bottom:16px"></textarea>

          <div style="display:flex;gap:10px">
            <button id="radio-div-cancel" style="flex:1;padding:10px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;cursor:pointer">取消</button>
            <button id="radio-div-ok" style="flex:1;padding:10px;font-size:14px;background:var(--accent);color:#fff;border:none;border-radius:10px;cursor:pointer">递交</button>
          </div>
        </div>`;
      document.body.appendChild(mask);
      const close = (data) => { try { mask.remove(); } catch (_) {} resolve(data); };
      mask.querySelector('#radio-div-cancel').onclick = () => close(null);
      // 点遮罩空白处关闭：要求按下和抬起都落在 mask 本身，避免输入框失焦/软键盘收起/点按钮时误触关闭
      let _maskDownOnSelf = false;
      mask.addEventListener('mousedown', (e) => { _maskDownOnSelf = (e.target === mask); });
      mask.addEventListener('click', (e) => { if (e.target === mask && _maskDownOnSelf) close(null); _maskDownOnSelf = false; });
      mask.querySelector('#radio-div-ok').onclick = () => {
        const question = (mask.querySelector('#radio-div-question')?.value || '').trim();
        if (!question) { UI.showToast('想问什么不能为空', 1500); return; }
        const name = (mask.querySelector('#radio-div-name')?.value || '').trim();
        const extra = (mask.querySelector('#radio-div-extra')?.value || '').trim();
        // 递交特效：弹窗内容化作光点消散，再关闭
        try { _radioDivinationSubmitFx(mask); } catch(_) {}
        setTimeout(() => close({ name, question, extra }), 620);
      };
      setTimeout(() => { try { mask.querySelector('#radio-div-question')?.focus(); } catch(_) {} }, 100);
    });
  }

  // 递交特效：把弹窗卡片化作一团上浮消散的符光（CSS 动画 phone-radio-div-submit）
  function _radioDivinationSubmitFx(mask) {
    const card = mask.querySelector('div');
    if (!card) return;
    // 锁住交互，避免动画期间重复点击
    mask.style.pointerEvents = 'none';
    card.classList.add('phone-radio-div-dissolve');
    // 在卡片上方撒一层上浮的光点
    const fx = document.createElement('div');
    fx.className = 'phone-radio-div-spark-layer';
    let dots = '';
    for (let i = 0; i < 14; i++) {
      const left = Math.round(Math.random() * 100);
      const delay = (Math.random() * 0.25).toFixed(2);
      const dur = (0.5 + Math.random() * 0.4).toFixed(2);
      const size = (3 + Math.random() * 4).toFixed(1);
      dots += `<span class="phone-radio-div-spark" style="left:${left}%;width:${size}px;height:${size}px;animation-delay:${delay}s;animation-duration:${dur}s"></span>`;
    }
    fx.innerHTML = dots;
    card.appendChild(fx);
  }

  // 互动暂停 → 处理抽奖玩法：玩家留名(或不参与) → 前端算20%中奖 → 生成开奖段（中奖则创建物流订单）→ 替换锚点 → 续播
  // opts.lottery = { name, prizeName }（玩家参与）；opts.skip=true 为不参与
  async function _radioHandleLotteryInteract(play, overlay, prog, ctx, resumeFn, opts) {
    const isSkip = !!(opts && opts.skip);
    let lotteryData = (opts && opts.lottery) || null;
    
    // 取奖品名：参与时从 lotteryData 拿；跳过时从正文锚点解析
    let prizeName = '';
    if (lotteryData) {
      prizeName = lotteryData.prizeName || '';
    } else {
      // skip：从正文里解析出抽奖锚点的参数
      const segs = _parseRadioReply(prog._body || '');
      const lotterySeg = segs.find(s => s.kind === 'interact' && s.interact === 'lottery' && !s.state);
      if (lotterySeg && Array.isArray(lotterySeg.params)) {
        prizeName = lotterySeg.params[0] || '';
      }
    }
    if (!prizeName) prizeName = '神秘礼物';

    // 前端计算中奖结果（20%中奖率）
    const playerName = (lotteryData && lotteryData.name) || '';
    const isWinner = !isSkip && (Math.random() < 0.2);

    // 锁定卡片
    const card = overlay.querySelector(`.phone-radio-detail-body .phone-radio-interact[data-seg-idx]`);
    const btns = card ? card.querySelectorAll('.phone-radio-interact-btn') : [];
    btns.forEach(b => { b.disabled = true; });
    UI.showToast('主播正在抽奖中…', 1500);

    // 锚点前的已播正文
    const anchor0 = (play && play.anchor) || '抽奖';
    const body0 = prog._body || _RADIO_FAKE_BODY;
    const anchorRe0 = new RegExp('^\\s*\\[\\[\\s*' + anchor0.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?:\\|[^\\]]*)?\\s*\\]\\]\\s*$', 'm');
    const priorBody = body0.split(anchorRe0)[0] || '';

    let segment = '';
    try {
      segment = await _radioGenLotterySegment(prog, { prizeName, playerName, isWinner, isSkip }, priorBody);
    } catch (e) {
      console.error('[抽奖结果生成]', e);
      segment = '';
    }
    if (!segment) {
      UI.showToast('生成失败，请重试', 1800);
      btns.forEach(b => { b.disabled = false; });
      return;
    }

    // 中奖：创建物流订单（走飞鸟收件）
    if (isWinner && playerName) {
      try {
        await _radioCreateLotteryOrder(prizeName, playerName);
      } catch (e) {
        console.error('[抽奖物流订单创建]', e);
      }
    }

    const newBody = body0.replace(anchorRe0, `[[${anchor0}:done]]\n${segment}`);
    prog._body = newBody;
    // 同步主线：记下本期玩家的抽奖互动摘要
    prog._lastInteract = isSkip
      ? `没参与抽奖，只听了开奖（奖品：${prizeName}）`
      : `用名字「${playerName || '匿名'}」参与了抽奖（奖品：${prizeName}），${isWinner ? '中奖了' : '没中'}`;
    if (typeof resumeFn === 'function') resumeFn(newBody);
  }

  // 调 AI 生成"抽奖开奖 + 收尾"段落：带奖品、中奖结果、已播前半段；主播公布结果并收尾
  async function _radioGenLotterySegment(prog, lottery, priorBody) {
    const funcConfig = Settings.getWorldvoiceConfig ? Settings.getWorldvoiceConfig() : {};
    let mainConfig = {};
    try { mainConfig = await API.getConfig(); } catch (_) { mainConfig = {}; }
    const url = (funcConfig.apiUrl || mainConfig.apiUrl || '').replace(/\/$/, '') + '/chat/completions';
    const key = funcConfig.apiKey || mainConfig.apiKey;
    const model = funcConfig.model || mainConfig.model;
    if (!url || !key || !model) { UI.showToast('请先配置功能模型', 1800); return ''; }

    let ctx = '';
    try { ctx = await _buildFullContext({ npcBrief: !_radioNeedNpcDetail(prog) }); } catch (_) {}
    let calBlock = '';
    try { calBlock = await _radioCalendarBlock(); } catch (_) {}
    let regionBlock = '';
    try { regionBlock = (_radioDataSourceOf(prog) === 'region') ? _radioRegionBlock() : ''; } catch (_) {}

    const djName = prog.dj || '主播';
    const guestName = prog.guest || '';
    const showName = prog.showName || prog.name || '本期节目';
    const priorText = (priorBody || prog._body || '').trim();

    const { prizeName, playerName, isWinner, isSkip } = lottery;
    
    let resultLine = '';
    if (isSkip) {
      resultLine = `玩家这次没有参与抽奖，只听结果。你需要自己编一个虚构听众的名字（例如"网名@小棠"、"昵称@成都的夜归人"，随机自拟，不要用世界观已知角色名），让这个虚构听众中奖。`;
    } else if (isWinner) {
      resultLine = `玩家参与了抽奖，留下的名字是「${playerName}」。结果：玩家中奖了！你必须在开奖时宣布「${playerName}」中奖，恭喜这个名字，奖品会通过物流系统送达。`;
    } else {
      resultLine = `玩家参与了抽奖，留下的名字是「${playerName}」，但这次没有中奖。你需要自己编一个虚构听众的名字（例如"网名@小棠"、"昵称@成都的夜归人"，随机自拟，不要用世界观已知角色名，也不要用玩家的名字「${playerName}」），让这个虚构听众中奖，自然地宣布中奖者是谁。`;
    }

    const sysPrompt = `${ctx}${calBlock ? '\n\n' + calBlock : ''}${regionBlock ? '\n\n' + regionBlock : ''}

你正在续写一档电台节目「${showName}」，本期已经播出了前半段，刚才主播发起了一个抽奖环节，现在结果已经出来了。要写"公布抽奖结果并据此把节目继续下去、最后收尾"这一段。

主播：${djName}${guestName ? `，嘉宾：${guestName}` : ''}。

【已播出的前半段正文】
${priorText}

【抽奖奖品】${prizeName}
【抽奖结果】（这是最终结果，直接用）
${resultLine}

【本环节要做的事】
1. 承接上文，主播先宣布抽奖通道关闭、正在抽取中奖者，然后利用这段"等抽奖"的空当做一点垫场，营造真实直播感。垫场方式可以是：
   - 插播一条电台广告/赞助商口播：内容以你现编为主，每次都换新的、不要重复老一套，可以是这个世界里会有的小店、产品、服务、活动等，带点电台广告特有的夸张吆喝感，轻松俏皮。
   - 或主播和嘉宾随口闲聊几句：调侃大家的参与热情、卖关子吊胃口、对结果做点悬念铺垫、说点废话拖时间。
   这段垫场可以稍微长一点，多说点废话，不要太快进入开奖，营造等待的悬念感。
2. 垫场之后，主播自然地宣布抽奖结果出来了，正式公布中奖者的名字。如果玩家中奖，必须准确宣布玩家留下的名字「${playerName}」；如果虚构听众中奖，宣布你自己编的那个名字。
3. 主播（和嘉宾）恭喜中奖者，可以简单说两句祝福的话，告知奖品会通过物流送达。
4. 公布并恭喜完中奖者后，不要跑题，承接节目主题做过渡（可以多说几句，不要太短促），然后把整期节目自然收尾（主播道别、片尾垫乐渐起），让节目完整结束。

【输出格式】（严格遵守，这是电台叙述流格式）
- 叙述行：不加任何前缀，只描写能被听到的声音（垫乐、音效、底噪、主播翻阅纸张声、语气、停顿、笑声等）；这是广播电台，绝不要写灯光、表情、动作姿态等任何视觉/画面信息。
- 主播一侧不要出现喝水、抽烟、点烟、打火机、咳嗽、清嗓、打哈欠、翻东西等生活化或私人小动作，保持主播应有的专业克制感——节目的氛围靠语气、停顿和留白营造，不靠这些小动作。
- 台词行：以「> 说话人：内容」开头，说话人是主播或嘉宾的名字。
- 每个台词行只放一两句话（约 15-40 字），说完就换行另起一行，不要把一大段塞进同一行。
- 措辞自拟，不要套用固定句式。
- 只输出正文，不要解释、不要 JSON、不要标题、不要 markdown 代码块。`;

    let raw = '';
    try {
      const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key },
        body: JSON.stringify({
          model,
          temperature: 0.9,
          max_tokens: 1800,
          messages: [
            { role: 'system', content: sysPrompt },
            { role: 'user', content: '请生成这段公布抽奖结果并完成节目收尾的正文。' }
          ]
        })
      });
      const data = await resp.json();
      raw = (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '';
    } catch (e) {
      console.error('[抽奖结果生成]', e);
      return '';
    }
    return _stripMainlineArtifacts(raw || '').trim();
  }

  // 互动暂停 → 处理问卜玩法：弹窗收集问卜信息（或不问卜）→ 生成"占卜解读+收尾"段 → 替换锚点 → 续播
  // opts.divination = { name, question, extra }（玩家参与）；opts.skip=true 为"不问卜"（主播为虚拟听众解一卦）
  async function _radioHandleDivinationInteract(play, overlay, prog, ctx, resumeFn, opts) {
    const isSkip = !!(opts && opts.skip);
    let div = (opts && opts.divination) || null;
    if (!isSkip && !div) return;  // 理论上参与时由调用方传入，缺失则不动

    // 锁定卡片按钮，显示生成中
    const card = overlay.querySelector(`.phone-radio-detail-body .phone-radio-interact[data-seg-idx]`);
    const allBtns = card ? card.querySelectorAll('.phone-radio-interact-btn') : [];
    const descEl = card ? card.querySelector('.phone-radio-interact-desc') : null;
    allBtns.forEach(b => { b.disabled = true; });
    if (descEl) descEl.textContent = isSkip ? '主播正在为听众解卦…' : '主播正在为你解卦…';
    UI.showToast(isSkip ? '主播正在为听众解卦…' : '主播正在为你解卦…', 1500);

    // 锚点前的已播正文
    const anchor0 = (play && play.anchor) || '问卜';
    const body0 = prog._body || _RADIO_FAKE_BODY;
    const anchorRe0 = new RegExp('^\\s*\\[\\[\\s*' + anchor0.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*\\]\\]\\s*$', 'm');
    const priorBody = body0.split(anchorRe0)[0] || '';

    let segment = '';
    try {
      segment = await _radioGenDivinationSegment(prog, isSkip ? null : div, priorBody);
    } catch (e) {
      console.error('[问卜解读生成]', e);
      segment = '';
    }
    if (!segment) {
      UI.showToast('生成失败，请重试', 1800);
      allBtns.forEach(b => { b.disabled = false; });
      if (descEl) descEl.textContent = (play && play.descPending) || '主播开放了问卜，把你的困惑递上来吧';
      return;
    }
    const newBody = body0.replace(anchorRe0, `[[${anchor0}:done]]\n${segment}`);
    prog._body = newBody;
    if (typeof resumeFn === 'function') resumeFn(newBody);
  }

  // 调 AI 生成"占卜解读 + 收尾"段落：带听众所问、已播前半段；主播为其占算解读并把节目收尾
  // div 为 null/无内容时走"无玩家问卜"分支（主播为虚拟听众解一卦）；priorBody 是 [[问卜]] 锚点之前的已播正文
  async function _radioGenDivinationSegment(prog, div, priorBody) {
    const funcConfig = Settings.getWorldvoiceConfig ? Settings.getWorldvoiceConfig() : {};
    let mainConfig = {};
    try { mainConfig = await API.getConfig(); } catch (_) { mainConfig = {}; }
    const url = (funcConfig.apiUrl || mainConfig.apiUrl || '').replace(/\/$/, '') + '/chat/completions';
    const key = funcConfig.apiKey || mainConfig.apiKey;
    const model = funcConfig.model || mainConfig.model;
    if (!url || !key || !model) { UI.showToast('请先配置功能模型', 1800); return ''; }

    let ctx = '';
    try { ctx = await _buildFullContext({ npcBrief: !_radioNeedNpcDetail(prog), lite: true, includeConvChars: true }); } catch (_) {}
    let calBlock = '';
    try { calBlock = await _radioCalendarBlock(); } catch (_) {}
    let regionBlock = '';
    try { regionBlock = (_radioDataSourceOf(prog) === 'region') ? _radioRegionBlock() : ''; } catch (_) {}

    const djName = prog.dj || '主播';
    const guestName = prog.guest || '';
    const showName = prog.showName || prog.name || '本期节目';
    const priorText = (priorBody || prog._body || '').trim();

    const hasDiv = !!(div && (div.question || '').trim());
    let divTask = '';
    if (hasDiv) {
      const askerName = (div.name || '').trim() || '一位匿名听众';
      const extraLine = (div.extra || '').trim() ? `\n     · 额外信息：${div.extra.trim()}` : '';
      divTask = `这是一位真实听众递上来的问卜，主播要为其占算解读：
     · 问卜人：${askerName}
     · 所问：${div.question.trim()}${extraLine}
   主播读出这位听众的所问，然后用本期所用的占卜方式（按世界观自适应，如求签/六爻/塔罗/星盘等，你自行选定并自然用起来）为其占算，给出解读和趋吉避凶的指点。若额外信息里有生辰、数字、牌号等，自然地用进占算里。`;
    } else {
      divTask = `这一期没有真实听众参与问卜。主播自己虚构一位匿名听众的问卜（自拟一个普通的困惑，如事业、感情、健康、抉择等，问卜人用"一位听众""来自某地的朋友"之类的匿名代称，不要用世界观已知角色），然后用本期所用的占卜方式（按世界观自适应，你自行选定）为其占算解读、给出指点。`;
    }

    const sysPrompt = `${ctx}${calBlock ? '\n\n' + calBlock : ''}${regionBlock ? '\n\n' + regionBlock : ''}

你正在续写一档电台节目「${showName}」，本期已经播出了前半段，刚才主播开放了"听众问卜"环节，现在要写"为听众占算解读、并把整期节目收尾完成"这一段。

主播：${djName}${guestName ? `，嘉宾：${guestName}` : ''}。

【已播出的前半段正文】
${priorText}

【本环节要做的事】
1. 承接上文，主播自然进入为听众解卦的环节（前面正文已经引出过开放问卜，这里直接开始）。
2. ${divTask}
3. 占卜解读要保留玄学应有的分寸：给的是趋吉避凶的指点、心境上的开解，不要铁口直断、不把话说死，点到为止留三分余地。不要给主线相关角色批命算运，也不要借占卜泄露主线剧情走向。
4. 解读完之后，不要跑题，承接节目主题做一段简短过渡，然后把整期节目自然收尾（主播道别、片尾垫乐渐起），让节目完整结束。

【输出格式】（严格遵守，这是电台叙述流格式）
- 叙述行：不加任何前缀，只描写能被听到的声音（空灵的垫乐、磬声铜铃、签筒铜钱的轻响、停顿、留白等）；这是广播电台，绝不要写灯光、表情、动作姿态等任何视觉/画面信息。
- 主播一侧不要出现喝水、抽烟、咳嗽等生活化或私人小动作——氛围靠语气、停顿和玄奥的措辞营造。
- 台词行：以「> 说话人：内容」开头，说话人是主播或嘉宾的名字。
- 每个台词行只放一两句话（约 15-40 字），说完就换行另起一行，不要把一大段塞进同一行。
- 措辞自拟，不要套用固定句式。具体口吻按主播人设走。
- 只输出正文，不要解释、不要 JSON、不要标题、不要 markdown 代码块。`;

    let raw = '';
    try {
      const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key },
        body: JSON.stringify({
          model,
          temperature: 0.9,
          max_tokens: 1800,
          messages: [
            { role: 'system', content: sysPrompt },
            { role: 'user', content: '请生成这段为听众占算解读并完成节目收尾的正文。' }
          ]
        })
      });
      const data = await resp.json();
      raw = (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '';
    } catch (e) {
      console.error('[问卜解读生成]', e);
      return '';
    }
    return _stripMainlineArtifacts(raw || '').trim();
  }

  // 创建抽奖中奖物流订单（飞鸟收件，配送时长读取桃宝/自定义桃宝配置）
  async function _radioCreateLotteryOrder(prizeName, winnerName) {
    const pd = await _getPhoneData();
    if (!pd) return;
    
    // 读取桃宝配送时长（默认3天=4320分钟，如果用户自定义了桃宝则优先用自定义时长）
    let deliveryMinutes = 4320; // 默认3天
    try {
      const shopMeta = pd.shopMeta || {};
      const shopConfig = shopMeta.shop || {};
      if (typeof shopConfig.etaValue === 'number' && shopConfig.etaValue > 0) {
        deliveryMinutes = (shopConfig.etaUnit === 'day') 
          ? shopConfig.etaValue * 1440 
          : shopConfig.etaValue;
      }
    } catch (_) {}

    const gameTime = _getGameTime();
    const order = {
      id: 'lottery_' + Utils.uuid().slice(0, 8),
      name: prizeName || '抽奖奖品',
      price: '',
shop: (_shopMeta?.radio?.name || '电台') + '抽奖',
        desc: `恭喜 ${winnerName} 在${_shopMeta?.radio?.name || '电台'}抽奖中获得`,
      target: '自己',
      time: new Date().toLocaleString(),
      status: 'delivering',
      deliveryMinutes: deliveryMinutes,
      orderGameTime: gameTime,
      feiniaoShip: true,
      feiniaoReceive: true,
      shipMode: deliveryMinutes < 1440 ? 'errand' : 'express',
      sender: '电台',
      shipItems: [{ 
        name: prizeName || '抽奖奖品', 
        count: 1, 
        effect: `在${_shopMeta?.radio?.name || '电台'}抽奖中获得的奖品`, 
        fromInventory: false 
      }],
    };

    const field = deliveryMinutes < 1440 ? 'takeoutOrders' : 'shopOrders';
    pd[field] = pd[field] || [];
    pd[field].push(order);
    pd[field] = pd[field].slice(-30);
    
    await _savePhoneData();
  }

  // 投票随机出票：给每个选项造一个听众票数。
  // - 玩家参与时（winnerIdx>=0）：70% 概率让玩家选的那个选项成为最高票，30% 概率让别的选项当票王。
  // - 玩家不投票时（winnerIdx<0）：各选项纯随机。
  // 返回 { counts:[..], percents:[..], total, topIdx }（counts 已含玩家那一票）
  const _VOTE_WIN_RATE = 0.7;  // 玩家选项成为票王的概率（可调）
  function _radioComputeVote(optionCount, winnerIdx) {
    const n = Math.max(2, optionCount || 2);
    // 基础票数：每个选项随机 200~1800
    const base = [];
    for (let i = 0; i < n; i++) base.push(200 + Math.floor(Math.random() * 1600));
    // 决定谁当票王
    let targetTop = -1;
    if (winnerIdx >= 0 && winnerIdx < n) {
      targetTop = (Math.random() < _VOTE_WIN_RATE) ? winnerIdx : -1;
      if (targetTop < 0) {
        // 30% 分支：从"非玩家选项"里随机挑一个当票王
        const others = [];
        for (let i = 0; i < n; i++) if (i !== winnerIdx) others.push(i);
        targetTop = others[Math.floor(Math.random() * others.length)];
      }
    }
    // 若指定了票王，把它抬到所有选项之上（在当前最大值基础上加一段随机增量）
    if (targetTop >= 0) {
      const curMax = Math.max(...base);
      base[targetTop] = curMax + 150 + Math.floor(Math.random() * 600);
    }
    // 玩家那一票加进去
    if (winnerIdx >= 0 && winnerIdx < n) base[winnerIdx] += 1;
    const total = base.reduce((a, b) => a + b, 0);
    const percents = base.map(c => Math.round(c / total * 100));
    let topIdx = 0;
    for (let i = 1; i < n; i++) if (base[i] > base[topIdx]) topIdx = i;
    return { counts: base, percents, total, topIdx };
  }

  // 互动暂停 → 处理投票玩法：玩家选项(或不投票) → 算票数(70%票王) → 生成结果段 → 替换锚点 → 续播
  // opts.vote = { optIdx, question, options }（玩家参与）；opts.skip=true 为不投票
  async function _radioHandleVoteInteract(play, overlay, prog, ctx, resumeFn, opts) {
    const isSkip = !!(opts && opts.skip);
    const voteData = (opts && opts.vote) || null;
    // 取问题/选项：参与时从 voteData 拿；跳过时从正文锚点解析
    let question = '';
    let options = [];
    if (voteData) {
      question = voteData.question || '';
      options = Array.isArray(voteData.options) ? voteData.options : [];
    } else {
      // skip：从正文里解析出投票锚点的参数
      const segs = _parseRadioReply(prog._body || '');
      const voteSeg = segs.find(s => s.kind === 'interact' && s.interact === 'vote' && !s.state);
      if (voteSeg && Array.isArray(voteSeg.params)) {
        question = voteSeg.params[0] || '';
        options = voteSeg.params.slice(1);
      }
    }
    if (!options.length) { UI.showToast('投票选项缺失', 1500); return; }

    const playerIdx = (voteData && typeof voteData.optIdx === 'number') ? voteData.optIdx : -1;
    const result = _radioComputeVote(options.length, isSkip ? -1 : playerIdx);

    // 锁定卡片
    const card = overlay.querySelector(`.phone-radio-detail-body .phone-radio-interact[data-seg-idx]`);
    const btns = card ? card.querySelectorAll('.phone-radio-vote-opt, .phone-radio-interact-btn') : [];
    btns.forEach(b => { b.disabled = true; });
    UI.showToast('正在统计投票…', 1500);

    // 锚点前的已播正文
    const anchor0 = (play && play.anchor) || '投票';
    const body0 = prog._body || _RADIO_FAKE_BODY;
    const anchorRe0 = new RegExp('^\\s*\\[\\[\\s*' + anchor0.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?:\\|[^\\]]*)?\\s*\\]\\]\\s*$', 'm');
    const priorBody = body0.split(anchorRe0)[0] || '';

    let segment = '';
    try {
      segment = await _radioGenVoteSegment(prog, { question, options, result, playerIdx: isSkip ? -1 : playerIdx }, priorBody);
    } catch (e) {
      console.error('[投票结果生成]', e);
      segment = '';
    }
    if (!segment) {
      UI.showToast('生成失败，请重试', 1800);
      btns.forEach(b => { b.disabled = false; });
      return;
    }
    const newBody = body0.replace(anchorRe0, `[[${anchor0}:done]]\n${segment}`);
    prog._body = newBody;
    // 同步主线：记下本期玩家的投票互动摘要
    prog._lastInteract = (isSkip || playerIdx < 0)
      ? `没参与投票${question ? `（话题：${question}）` : ''}，只听了结果`
      : `参与了投票${question ? `（话题：${question}）` : ''}，投给了「${options[playerIdx] || ''}」`;
    if (typeof resumeFn === 'function') resumeFn(newBody);
  }

  // 调 AI 生成"投票结果 + 收尾"段落：带全资料 + 已播前半段 + 投票结果数据；主播公布结果并据此继续节目并收尾
  async function _radioGenVoteSegment(prog, vote, priorBody) {
    const funcConfig = Settings.getWorldvoiceConfig ? Settings.getWorldvoiceConfig() : {};
    let mainConfig = {};
    try { mainConfig = await API.getConfig(); } catch (_) { mainConfig = {}; }
    const url = (funcConfig.apiUrl || mainConfig.apiUrl || '').replace(/\/$/, '') + '/chat/completions';
    const key = funcConfig.apiKey || mainConfig.apiKey;
    const model = funcConfig.model || mainConfig.model;
    if (!url || !key || !model) { UI.showToast('请先配置功能模型', 1800); return ''; }

    let ctx = '';
    try { ctx = await _buildFullContext({ npcBrief: !_radioNeedNpcDetail(prog) }); } catch (_) {}
    let calBlock = '';
    try { calBlock = await _radioCalendarBlock(); } catch (_) {}
    let regionBlock = '';
    try { regionBlock = (_radioDataSourceOf(prog) === 'region') ? _radioRegionBlock() : ''; } catch (_) {}

    const djName = prog.dj || '主播';
    const guestName = prog.guest || '';
    const showName = prog.showName || prog.name || '本期节目';
    const priorText = (priorBody || prog._body || '').trim();

    const { question, options, result, playerIdx } = vote;
    // 投票结果文本
    const resultLines = options.map((opt, i) => {
      const mark = (i === playerIdx) ? '（这是玩家投的）' : '';
      const topMark = (i === result.topIdx) ? '【最高票】' : '';
      return `  - ${opt}：${result.percents[i]}%（${result.counts[i]}票）${topMark}${mark}`;
    }).join('\n');
    const playerLine = playerIdx >= 0
      ? `玩家参与了投票，投给了「${options[playerIdx]}」。玩家投的${playerIdx === result.topIdx ? '正好是最高票（跟大多数人想到一块了）' : '不是最高票（属于少数派，最高票是「' + options[result.topIdx] + '」）'}。`
      : `玩家这次没有参与投票，只听结果。`;

    // 连载类（如长夜连载）：投票是"剧情抉择点"，公布结果后要顺着票王选项把剧情往下推进、集末留钩子，
    // 而不是当场收尾结束节目。其它标签：轻松话题投票，公布结果聊两句后正常收尾。
    const isSerial = _radioIsSerialTag(prog);
    const topOption = options[result.topIdx] || '';
    const taskBlock = isSerial
      ? `【本环节要做的事】（这是连载故事的关键抉择点，听众刚投票决定了主角接下来怎么走。注意：这是深夜怪谈，要保持沉浸，不要用播报体破坏氛围）
1. 不要宣布"投票通道关闭""票数统计中""XX%的听众选择了"这类生硬的播报。也不要报具体的百分比数字。
2. 用讲故事的口吻，把听众的选择自然地接回剧情。主播可以轻声把"大家的选择"道出来，再顺势续讲——比如"你们当中的大多数人，都想让他推开那扇门……那么，他就推开了"，或"犹豫的人不少，可最终，更多的声音指向了那条路"。让"听众做了选择"这件事融进叙述的语气里，而不是跳出故事念结果。
3. 票数走向只做模糊的叙述化处理（"大多数人""也有人迟疑""几乎所有人都……"），点出最高票的方向是「${topOption}」即可，不要报数字。
4. 关键：顺着最高票选项「${topOption}」这个方向，把故事接着往下讲。主角就照着这个选择行动，看看会发生什么。把这一段剧情讲得有血有肉、保持怪谈应有的惊悚诡异氛围，该铺垫铺垫、该渗人渗人。
5. 这一段结束时，不要把整个故事讲完、也不要彻底收尾结束节目——而是在恰当处留下新的悬念/钩子（一句没解释的怪事、一个突然的转折、一个让人脊背发凉的发现），告诉听众"欲知后事，下回分解"，再以主播道别、片尾垫乐渐起的方式结束本集。`
      : `【本环节要做的事】
1. 承接上文，主播先宣布投票通道关闭、票数正在统计中，然后利用这段"等统计"的空当做一点垫场，营造真实直播感。垫场二选一或混着来：
   - 插播一条电台广告/赞助商口播：内容以你现编为主，每次都换新的、不要重复老一套，可以是这个世界里会有的小店、产品、服务、活动等，带点电台广告特有的夸张吆喝感，轻松俏皮。
   - 或主播和嘉宾随口闲聊几句：调侃大家的投票热情、卖关子吊胃口、对结果做点悬念铺垫。
   这段垫场不要太长，一小段即可。
2. 垫场之后，主播自然地宣布票数统计完毕，正式公布投票结果。报出大致的票数走向或百分比，点出哪个选项票最高。
3. 主播（和嘉宾）针对投票结果做出真实、贴合人设与本期主题的回应：可以点评大众的选择、可以顺着多数派或少数派的立场展开、可以借结果引出后续内容。具体怎么用这个结果，贴合本档节目的调性来。
4. 如果玩家参与了且属于少数派，可以自然地用一句话照顾到"也有人投了另一个"的角度，但不要直接对玩家个人喊话（电台不知道具体是谁投的）。
5. 公布并聊完结果后，不要跑题，承接节目主题做简短过渡，然后把整期节目自然收尾（主播道别、片尾垫乐渐起），让节目完整结束。`;

    const sysPrompt = `${ctx}${calBlock ? '\n\n' + calBlock : ''}${regionBlock ? '\n\n' + regionBlock : ''}

你正在续写一档电台节目「${showName}」，本期已经播出了前半段，刚才主播发起了一个听众投票，现在票数已经出来了。要写"公布投票结果并据此把节目继续下去${isSerial ? '、顺着票数最高的方向把剧情往下讲、集末留钩子' : '、最后收尾'}"这一段。

主播：${djName}${guestName ? `，嘉宾：${guestName}` : ''}。

【已播出的前半段正文】
${priorText}

【投票问题】${question}
【投票结果】（这是最终票数，已经统计好，直接用，不要改数字）
${resultLines}
${playerLine}

${taskBlock}

【输出格式】（严格遵守，这是电台叙述流格式）
- 叙述行：不加任何前缀，只描写能被听到的声音（垫乐、音效、底噪、主播翻阅纸张声、语气、停顿、笑声等）；这是广播电台，绝不要写灯光、表情、动作姿态等任何视觉/画面信息。
- 主播一侧不要出现喝水、抽烟、点烟、打火机、咳嗽、清嗓、打哈欠、翻东西等生活化或私人小动作，保持主播应有的专业克制感——节目的氛围靠语气、停顿和留白营造，不靠这些小动作。
- 台词行：以「> 说话人：内容」开头，说话人是主播或嘉宾的名字。
- 每个台词行只放一两句话（约 15-40 字），说完就换行另起一行，不要把一大段塞进同一行。
- 措辞自拟，不要套用固定句式。
- 只输出正文，不要解释、不要 JSON、不要标题、不要 markdown 代码块。`;

    let raw = '';
    try {
      const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key },
        body: JSON.stringify({
          model,
          temperature: 0.9,
          max_tokens: 1600,
          messages: [
            { role: 'system', content: sysPrompt },
            { role: 'user', content: '请生成这段公布投票结果并完成节目收尾的正文。' }
          ]
        })
      });
      const data = await resp.json();
      raw = (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '';
    } catch (e) {
      console.error('[投票结果生成]', e);
      return '';
    }
    return _stripMainlineArtifacts(raw || '').trim();
  }


  // ===== 点歌玩法 =====
  // 弹窗：从音乐库选歌 / 现写歌名 / 不点歌，并填署名、送给谁、寄语
  // 返回 null（取消）或 { trackId, title, artist, desc, lrc, fromName, toName, message }
  // trackId 有值=真点歌（节目末尾会真的播放该曲）；trackId 为空=现写歌（不真放）
  function _radioSongInput() {
    return new Promise((resolve) => {
      const defName = _radioPlayerName();
      const tracks = (typeof Music !== 'undefined') ? (Music.getTracks() || []) : [];
      const mask = document.createElement('div');
      mask.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;padding:20px';
      // 歌库列表 HTML（库空则不渲染这块）
      let libHtml = '';
      if (tracks.length) {
        const items = tracks.map(t =>
          `<div class="radio-song-item" data-tid="${Utils.escapeHtml(t.id)}" style="padding:9px 12px;border:1px solid var(--border);border-radius:10px;margin-bottom:8px;cursor:pointer;background:var(--bg-tertiary)">
            <div style="font-size:14px;color:var(--text);font-weight:500">${Utils.escapeHtml(t.title || '未命名')}</div>
            <div style="font-size:12px;color:var(--text-secondary);margin-top:2px">${Utils.escapeHtml(t.artist || '未知歌手')}</div>
          </div>`
        ).join('');
        libHtml = `
          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">从音乐库点一首（点了会在节目末尾真的播放）</label>
          <div id="radio-song-lib" style="max-height:180px;overflow-y:auto;margin-bottom:12px">${items}</div>`;
      }
      mask.innerHTML = `
        <div style="background:var(--bg);border:1px solid var(--border);border-radius:14px;padding:20px;max-width:360px;width:100%;color:var(--text);max-height:84vh;overflow-y:auto">
          <div style="font-size:15px;font-weight:600;margin-bottom:4px">${_radioRequestSvg()}点一首歌</div>
          <div style="font-size:12px;color:var(--text-secondary);margin-bottom:16px">选库里的歌主播会真的播放；现写一首主播只点评不播放</div>

          ${libHtml}

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">或者现写一首想听的歌（库里没有，不会真的播放）</label>
          <input id="radio-song-title" type="text" maxlength="40" placeholder="歌名" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:8px">
          <input id="radio-song-artist" type="text" maxlength="30" placeholder="歌手（可选）" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:12px">

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">点歌人</label>
          <input id="radio-song-from" type="text" maxlength="16" value="${Utils.escapeHtml(defName)}" placeholder="你的昵称" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:12px">

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">送给谁（可选）</label>
          <input id="radio-song-to" type="text" maxlength="20" placeholder="例如：给楼下便利店的店长" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;margin-bottom:12px">

          <label style="display:block;font-size:12px;color:var(--text-secondary);margin-bottom:5px">寄语（可选）</label>
          <textarea id="radio-song-msg" maxlength="200" rows="3" placeholder="想说的话，主播会念出来…" style="width:100%;box-sizing:border-box;padding:9px 12px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;outline:none;resize:none;margin-bottom:16px"></textarea>

          <div style="display:flex;gap:10px">
            <button id="radio-song-cancel" style="flex:1;padding:10px;font-size:14px;background:var(--bg-tertiary);color:var(--text);border:1px solid var(--border);border-radius:10px;cursor:pointer">取消</button>
            <button id="radio-song-send" style="flex:1;padding:10px;font-size:14px;background:var(--accent);color:#fff;border:none;border-radius:10px;cursor:pointer">点这首</button>
          </div>
        </div>`;
      document.body.appendChild(mask);
      let selectedTid = '';
      const close = (val) => { try { mask.remove(); } catch (_) {} resolve(val); };
      mask.querySelector('#radio-song-cancel').onclick = () => close(null);
      // 点遮罩空白处关闭：要求按下和抬起都落在 mask 本身，避免输入框失焦/软键盘收起导致的误触关闭
      let _maskDownOnSelf = false;
      mask.addEventListener('mousedown', (e) => { _maskDownOnSelf = (e.target === mask); });
      mask.addEventListener('click', (e) => { if (e.target === mask && _maskDownOnSelf) close(null); _maskDownOnSelf = false; });
      // 歌库项点选（互斥高亮；选库歌时清空现写输入）
      const titleInput = mask.querySelector('#radio-song-title');
      const artistInput = mask.querySelector('#radio-song-artist');
      const lib = mask.querySelector('#radio-song-lib');
      if (lib) {
        lib.addEventListener('click', (e) => {
          const item = e.target.closest('.radio-song-item');
          if (!item) return;
          const tid = item.getAttribute('data-tid');
          if (selectedTid === tid) {
            selectedTid = '';
            item.style.borderColor = 'var(--border)';
            item.style.background = 'var(--bg-tertiary)';
          } else {
            selectedTid = tid;
            lib.querySelectorAll('.radio-song-item').forEach(el => {
              el.style.borderColor = 'var(--border)';
              el.style.background = 'var(--bg-tertiary)';
            });
            item.style.borderColor = 'var(--accent)';
            item.style.background = 'rgba(0,0,0,0.04)';
            // 选了库歌，清空现写
            titleInput.value = '';
            artistInput.value = '';
          }
        });
      }
      // 输入现写歌时取消库歌选中
      titleInput.addEventListener('input', () => {
        if (titleInput.value.trim() && selectedTid) {
          selectedTid = '';
          if (lib) lib.querySelectorAll('.radio-song-item').forEach(el => {
            el.style.borderColor = 'var(--border)';
            el.style.background = 'var(--bg-tertiary)';
          });
        }
      });
      mask.querySelector('#radio-song-send').onclick = () => {
        const fromName = (mask.querySelector('#radio-song-from').value || '').trim() || '一位听众';
        const toName = (mask.querySelector('#radio-song-to').value || '').trim();
        const message = (mask.querySelector('#radio-song-msg').value || '').trim();
        if (selectedTid) {
          // 真点歌：从库里取完整信息
          const t = tracks.find(x => x.id === selectedTid);
          if (!t) { UI.showToast('歌曲不存在', 1500); return; }
          close({ trackId: t.id, title: t.title || '未命名', artist: t.artist || '', desc: t.desc || '', lrc: t.lrc || '', fromName, toName, message });
          return;
        }
        // 现写歌
        const title = (titleInput.value || '').trim();
        if (!title) { UI.showToast('请选一首库里的歌，或写下想听的歌名', 1800); return; }
        const artist = (artistInput.value || '').trim();
        close({ trackId: '', title, artist, desc: '', lrc: '', fromName, toName, message });
      };
    });
  }

  // 互动暂停 → 处理点歌玩法：弹窗收集 → 生成报歌+点评+收尾段 → 替换锚点 → 续播
  // 真点歌时把 trackId 记到 prog._pendingSongId，节目播完后由 onFinish 触发真实播放
  // opts.skip=true 为"不点歌"路径（主播播虚拟听众点的歌，不真放）
  async function _radioHandleSongInteract(play, overlay, prog, ctx, resumeFn, opts) {
    const isSkip = !!(opts && opts.skip);
    let song = null;
    if (!isSkip) {
      song = await _radioSongInput();
      if (!song) return;  // 取消：保持暂停态
    }
    // 锁卡片
    const card = overlay.querySelector(`.phone-radio-detail-body .phone-radio-interact[data-seg-idx]`);
    const allBtns = card ? card.querySelectorAll('.phone-radio-interact-btn') : [];
    const descEl = card ? card.querySelector('.phone-radio-interact-desc') : null;
    allBtns.forEach(b => { b.disabled = true; });
    if (descEl) descEl.textContent = '主播正在准备这首歌…';
    UI.showToast('主播正在准备这首歌…', 1500);

    // 锚点前已播正文
    const anchor0 = (play && play.anchor) || '点歌';
    const body0 = prog._body || _RADIO_FAKE_BODY;
    const anchorRe0 = new RegExp('^\\s*\\[\\[\\s*' + anchor0.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*\\]\\]\\s*$', 'm');
    const priorBody = body0.split(anchorRe0)[0] || '';

    const segment = await _radioGenSongSegment(prog, song, priorBody);
    if (!segment) {
      UI.showToast('生成失败，请重试', 1800);
      allBtns.forEach(b => { b.disabled = false; });
      if (descEl) descEl.textContent = (play && play.descPending) || '主播开放了点歌通道，要不要点一首？';
      return;
    }
    // 真点歌：记下要播放的 songId，节目 TTS 念完后触发
    prog._pendingSongId = (song && song.trackId) ? song.trackId : '';
    const newBody = body0.replace(anchorRe0, `[[${anchor0}:done]]\n${segment}`);
    prog._body = newBody;
    // 同步主线：记下本期玩家的点歌互动摘要
    prog._lastInteract = isSkip
      ? '没点歌，听主播放了别的听众点的歌'
      : `点了一首歌《${(song && song.title) || '未命名'}》${song && song.artist ? `（${song.artist}）` : ''}${song && song.toName ? `，点给${song.toName}` : ''}${song && song.message ? `，寄语：${(song.message || '').slice(0, 40)}` : ''}`;
    if (typeof resumeFn === 'function') resumeFn(newBody);
  }

  // 调 AI 生成"报歌 + 点评 + 收尾"段落：带全资料 + 已播前半段 + 歌曲信息（歌名/歌手/描述/歌词）+ 点歌人/寄语
  async function _radioGenSongSegment(prog, song, priorBody) {
    const funcConfig = Settings.getWorldvoiceConfig ? Settings.getWorldvoiceConfig() : {};
    const mainConfig = await API.getConfig();
    const url = (funcConfig.apiUrl || mainConfig.apiUrl || '').replace(/\/$/, '') + '/chat/completions';
    const key = funcConfig.apiKey || mainConfig.apiKey;
    const model = funcConfig.model || mainConfig.model;
    if (!url || !key || !model) { UI.showToast('请先配置功能模型', 1800); return ''; }

    let ctx = '';
    try { ctx = await _buildFullContext({ npcBrief: !_radioNeedNpcDetail(prog) }); } catch (_) {}
    const calBlock = await _radioCalendarBlock();
    const regionBlock = (_radioDataSourceOf(prog) === 'region') ? _radioRegionBlock() : '';

    const djName = prog.dj || '主播';
    const guestName = prog.guest || '';
    const showName = prog.showName || prog.name || '本期节目';
    const priorText = (priorBody || prog._body || '').trim();

    // 歌曲信息块（玩家参与时有；不点歌时让 AI 现编一首虚拟听众点的歌）
    let songBlock = '';
    let songTask = '';
    if (song) {
      const isReal = !!song.trackId;
      const lrcText = song.lrc ? song.lrc.substring(0, 2000) : '（无歌词）';
      songBlock = `【听众点的歌】
- 歌名：${song.title || '未命名'}
- 歌手：${song.artist || '未知'}
- 歌曲描述：${song.desc || '（无）'}
- 点歌人：${song.fromName || '一位听众'}
${song.toName ? `- 送给：${song.toName}` : ''}
${song.message ? `- 寄语：${song.message}` : ''}
- 歌词：
${lrcText}`;
      songTask = `这是听众真实点的歌${isReal ? '（节目末尾会真的播放这首歌）' : ''}。`;
    } else {
      songBlock = `【点歌情况】这次没有具体听众点歌，由你现编一位虚拟听众点的歌（一首符合本世界观、贴合节目调性的歌），自拟歌名、歌手、点歌人和一小段寄语。`;
      songTask = '这是你现编的虚拟听众点歌，主播不会真的播放音频。';
    }

    const sysPrompt = `${ctx}${calBlock ? '\n\n' + calBlock : ''}${regionBlock ? '\n\n' + regionBlock : ''}

你正在续写一档电台节目「${showName}」，本期已经播出了前半段，刚才主播开放了听众点歌环节。现在要写"主播报歌、念寄语、点评这首歌，然后把节目收尾"这一段——这是整期节目的结尾段。

主播：${djName}${guestName ? `，嘉宾：${guestName}` : ''}。

【已播出的前半段正文】
${priorText}

${songBlock}

【本环节要做的事】
1. 承上启下：先承接前半段聊过的话题，用一两句自然地把它收个尾，如果能跟即将要点的这首歌的情绪/主题搭上一点关系就更好（不必生硬关联），再顺势把话头转到点歌、报歌上。
2. 主播自然地报出这首点的歌（歌名、歌手），${song && song.fromName ? `念出点歌人「${song.fromName}」${song.toName ? `点给「${song.toName}」` : ''}` : '说说是哪位听众点的'}${song && song.message ? '，并把寄语自然地念出来、做点温暖回应' : ''}。
3. 主播（和嘉宾）对这首歌做一段真诚、贴合人设的点评：可以聊歌词意境、旋律氛围、适合什么心境听、勾起的联想或回忆等。${songTask}
4. 点评结束后，主播说一句结束语向听众道别（措辞自拟），然后顺势说"接下来就把这首歌完整放给大家、安静聆听"之类的话，把节目交给音乐。
5. 最后用叙述行描写：主播的声音渐渐减弱、节目进入尾声、（点的这首歌的）旋律缓缓响起，节目在歌声中收束。整期节目到此自然完整结束。

【输出格式】（严格遵守，这是电台叙述流格式）
- 叙述行：不加任何前缀，只描写能被听到的声音（主播语气、声音渐弱、片尾旋律响起、垫乐音效等）；这是广播电台，绝不要写灯光、表情、动作姿态等任何视觉/画面信息。
- 主播一侧不要出现喝水、抽烟、点烟、打火机、咳嗽、清嗓、打哈欠、翻东西等生活化或私人小动作，保持主播应有的专业克制感——节目的氛围靠语气、停顿和留白营造，不靠这些小动作。
- 台词行：以「> 说话人：内容」开头，说话人是主播或嘉宾的名字。
- 每个台词行只放一两句话（约 15-40 字），说完就换行另起一行，不要把一大段塞进同一行。
- 措辞自拟，不要套用固定句式。
- 只输出正文，不要解释、不要 JSON、不要标题、不要 markdown 代码块。`;

    let raw = '';
    try {
      const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key },
        body: JSON.stringify({
          model,
          temperature: 0.9,
          max_tokens: 1600,
          messages: [
            { role: 'system', content: sysPrompt },
            { role: 'user', content: '请生成这段报歌、点评并完成节目收尾的正文。' }
          ]
        })
      });
      const data = await resp.json();
      raw = (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '';
    } catch (e) {
      console.error('[点歌段生成]', e);
      return '';
    }
    return _stripMainlineArtifacts(raw || '').trim();
  }

  // 节目自然播完后：若有待播的点歌曲目，关底噪 → 真实播放该曲
  function _radioMaybePlaySong(prog) {
    try {
      const sid = prog && prog._pendingSongId;
      if (!sid) return;
      prog._pendingSongId = '';  // 消费一次，避免重复触发
      if (typeof Music === 'undefined') return;
      _RadioSpeaker.stopNoise();  // 放歌前关掉电台底噪，安静听歌
      Music.play(sid);
    } catch (e) { console.error('[点歌播放]', e); }
  }


  async function _radioOpenDetail(catId, idx, opts) {
    opts = opts || {};
    try { _radioRefreshGlobalPrefsCache(await _getPhoneData()); } catch (_) {}
    const fromMine = !!opts.fromMine;
    // 从「我的」进入：先展示"待更新"闸门——顶部节目名换成下期预告名，中间放「收听本期更新」按钮，点了才生成本期新内容
    const next = fromMine ? _radioNextPreviewOf((await _getPhoneData()).radioPrograms?.[catId]?.[idx]) : null;
    let updateGate = fromMine && !!opts.showUpdateGate;
    const pd = await _getPhoneData();
    const programs = (pd.radioPrograms && pd.radioPrograms[catId]) || [];
    const p = programs[idx];
    if (!p) { UI.showToast('节目不存在', 1500); return; }

    // 闸门态下不立即生成；非闸门态沿用旧逻辑
    const needGen = !updateGate && !p._body;
    // 新闻类时间限制：18:30-21:00 才允许生成
    if (needGen && !_radioNewsTimeAllowed(p)) {
      UI.showToast('晚间新闻仅在 18:30–21:00 播出', 2500);
      return;
    }
// 深夜情感类时间限制：22:00-02:00 才允许生成
      if (needGen && !_radioEmotionTimeAllowed(p)) {
        UI.showToast('深夜情感节目仅在 22:00–02:00 播出', 2500);
        return;
      }
      // 怪谈类时间限制：21:00-04:00 才允许生成
      if (needGen && !_radioGhostTimeAllowed(p)) {
        UI.showToast('怪谈节目仅在 21:00–04:00 播出', 2500);
        return;
      }
    if (needGen) p._generating = true;
    // 已有正文的台（再次收听）→ 直接确保在「我的」订阅里；首次生成的在生成成功后再加
    if (!updateGate && !needGen) { try { await _radioSubscribeStation(catId, p); } catch (_) {} }

    // 头部圆形头像：有封面用封面，否则主题色底
    const avatarHtml = p.cover
      ? `<img src="${Utils.escapeHtml(p.cover)}" alt="">`
      : `<div class="phone-radio-detail-avatar-fallback">${Utils.escapeHtml((p.name || '电')[0])}</div>`;

    const fmText = p.fm ? `FM ${Utils.escapeHtml(String(p.fm))}` : '';
const hostLine = `主播 ${Utils.escapeHtml(_radioDisplayName(p.dj) || '匿名')}${p.guest ? ` · 嘉宾 ${Utils.escapeHtml(_radioDisplayName(p.guest))}` : ''}`;
      const tags = (p.tags || []).map(t => `<span class="phone-radio-card-tag">${Utils.escapeHtml(t)}</span>`).join('');

    // 正文：闸门态不渲染旧正文（等点更新后重新生成）；否则已生成则渲染真实节目
    const bodyRaw = updateGate ? '' : (p._body || '');
    const duration = p._duration || _radioDurationOf(p);
    const segHtml = bodyRaw ? _radioRenderSegments(bodyRaw, p) : '';
    // 顶部节目名：闸门态显示「下期节目」预告名，引导用户收听更新
    const showTitle = updateGate
      ? ((next && next.name) ? next.name : '下期节目')
      : (p.showName || '本期节目');

    const overlay = document.createElement('div');
    overlay.className = 'phone-radio-detail';
    overlay.innerHTML = `
      <div class="phone-radio-detail-head">
        <button class="phone-radio-detail-back" id="phone-radio-detail-back">
          <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 12H5"/><path d="m12 5-7 7 7 7"/></svg>
        </button>
        <div class="phone-radio-detail-headinfo">
          <div class="phone-radio-detail-name">${Utils.escapeHtml(p.name || '电台')}</div>
          <div class="phone-radio-detail-fm">${fmText}</div>
        </div>
        <button class="phone-radio-detail-set" id="phone-radio-detail-set" title="电台设置">
          ${_uiIcon('settings', 20)}
        </button>
        <div class="phone-radio-detail-avatar">${avatarHtml}</div>
      </div>
      <div class="phone-radio-detail-meta">
        <div class="phone-radio-detail-show">${Utils.escapeHtml(showTitle)}</div>
        <div class="phone-radio-detail-info-row">
          <span class="phone-radio-detail-tags">${tags}</span>
          <span class="phone-radio-detail-host">${hostLine}</span>
          <span class="phone-radio-detail-dur">⏱ ${Utils.escapeHtml(duration)}</span>
        </div>
      </div>
      <div class="phone-radio-detail-scroll">
        ${updateGate ? `
        <div class="phone-radio-detail-updategate" id="phone-radio-detail-updategate" style="display:flex;flex-direction:column;align-items:center;justify-content:center;padding:48px 24px;text-align:center">
          <svg viewBox="0 0 24 24" width="44" height="44" fill="none" stroke="var(--accent)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="margin-bottom:16px"><path d="M4.9 19.1C1 15.2 1 8.8 4.9 4.9"/><path d="M7.8 16.2c-2.3-2.3-2.3-6.1 0-8.5"/><circle cx="12" cy="12" r="2"/><path d="M16.2 7.8c2.3 2.3 2.3 6.1 0 8.5"/><path d="M19.1 4.9C23 8.8 23 15.2 19.1 19.1"/></svg>
          <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:6px">${Utils.escapeHtml((next && next.name) ? next.name : '下期节目')}</div>
          ${(next && next.desc) ? `<div style="font-size:12.5px;line-height:1.6;color:var(--text-secondary);max-width:280px;margin-bottom:22px">${Utils.escapeHtml(next.desc)}</div>` : '<div style="margin-bottom:22px"></div>'}
          <button type="button" id="phone-radio-update-btn" style="padding:11px 28px;background:var(--accent);color:#111;border:none;border-radius:22px;font-size:14px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:8px">
            <svg xmlns="http://www.w3.org/2000/svg" width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><polygon points="6 3 20 12 6 21 6 3"/></svg>
            收听本期更新
          </button>
        </div>` : ''}
        <div class="phone-radio-detail-hint" id="phone-radio-detail-hint" style="${updateGate ? 'display:none' : ''}">${p._generating ? '节目准备中…' : '点击播放按钮开始'}</div>
        <div class="phone-radio-detail-body">${segHtml}</div>
          <div class="phone-radio-detail-interact" id="phone-radio-detail-interact">
            <!-- 互动玩法占位：投票/点歌/抽奖/连线 -->
          </div>
          <div class="phone-radio-detail-sync" id="phone-radio-detail-sync" style="${_radioIsNewsTag(p) && bodyRaw && !_radioHasPendingInteract(bodyRaw) ? '' : 'display:none'};padding:14px 16px 24px">
            <button type="button" id="phone-radio-sync-btn" style="width:100%;padding:12px;background:var(--bg-tertiary);color:var(--text);border:none;border-radius:12px;font-size:14px;font-weight:500;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px">
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" x2="12" y1="2" y2="15"/></svg>
              将新闻同步至主线
            </button>
          </div>
        </div>
      <div class="phone-radio-detail-player">
        <div class="phone-radio-player-progress">
          <div class="phone-radio-spectrum" id="phone-radio-spectrum">${_radioSpectrumBars(40)}</div>
        </div>
        <div class="phone-radio-player-controls">
          <button class="phone-mdetail-ctrl" id="phone-radio-skip" title="跳过动画">${_musicSvg('skipDown')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-prev">${_musicSvg('prev')}</button>
          <button class="phone-mdetail-ctrl phone-mdetail-play" id="phone-radio-play">${_musicSvg('playBig')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-next">${_musicSvg('nextTrack')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-share" title="分享本期">${_uiIcon('share', 22)}</button>
        </div>
      </div>`;
    const shell = document.querySelector('#phone-modal .phone-shell') || document.body;
    shell.appendChild(overlay);
    const back = overlay.querySelector('#phone-radio-detail-back');
    // 关闭详情页：停朗读 + 停底噪 + 移除 overlay；从「我的」进来则回到「我的」tab，否则回该分类预览页
    const closeDetail = async () => {
      _RadioSpeaker.stop();
      _RadioSpeaker.stopNoise();
      _radioClearScare();
      overlay.remove();
      try {
        const pd2 = await _getPhoneData();
        if (fromMine) {
          _radioHomeTab = 'mine';
          _renderRadio(pd2);
        } else {
          _radioCardIdx = idx;
          _renderRadioCategory(pd2, catId);
        }
      } catch (_) {}
    };
    if (back) back.onclick = closeDetail;
    // 进入详情页时启动底噪（全局偏好开了才启）
    if (_radioGlobalPrefsCache.noise) _RadioSpeaker.startNoise();
    // 怪谈类：启动随机惊吓特效计时
    _radioScheduleScare(overlay, p);
    const setBtn = overlay.querySelector('#phone-radio-detail-set');
    if (setBtn) setBtn.onclick = () => _radioOpenSettings(catId, idx);
    // 分享按钮：把当前期正文拼成一张图导出
    const shareBtn = overlay.querySelector('#phone-radio-share');
    if (shareBtn) shareBtn.onclick = () => _radioShareProgram(p);
    // 同步至主线按钮：弹句子级勾选面板
    const syncBtn = overlay.querySelector('#phone-radio-sync-btn');
    if (syncBtn) syncBtn.onclick = () => _radioSyncToMainline(p);
    // 跳过动画：停止逐句朗读/推进，一次性显示全部内容
    const skipBtn = overlay.querySelector('#phone-radio-skip');
    if (skipBtn) {
      skipBtn.onclick = () => {
        if (_RadioSpeaker.isSpeaking()) _RadioSpeaker.stop();
        const playBtnEl = overlay.querySelector('#phone-radio-play');
        if (playBtnEl) playBtnEl.innerHTML = _musicSvg('playBig');
        const spectrumEl = overlay.querySelector('#phone-radio-spectrum');
        if (spectrumEl) spectrumEl.classList.remove('playing');
        _radioRevealAll(overlay);
      };
    }
    // 「收听本期更新」按钮（仅从「我的」进入的闸门态有）：当前期归档进历史 → 清旧正文 → 生成新一期 → 进入正常播放流程
    const updateBtn = overlay.querySelector('#phone-radio-update-btn');
    if (updateBtn) {
      updateBtn.onclick = async () => {
        // 新闻类时间限制：18:30-21:00 才允许更新
        if (!_radioNewsTimeAllowed(p)) {
          UI.showToast('晚间新闻仅在 18:30–21:00 播出', 2500);
          return;
        }
        // 深夜情感类时间限制：22:00-02:00 才允许更新
        if (!_radioEmotionTimeAllowed(p)) {
          UI.showToast('深夜情感节目仅在 22:00–02:00 播出', 2500);
          return;
        }
        // 怪谈类时间限制：21:00-04:00 才允许更新
        if (!_radioGhostTimeAllowed(p)) {
          UI.showToast('怪谈节目仅在 21:00–04:00 播出', 2500);
          return;
        }
        overlay.remove();
        _RadioSpeaker.stop();
        _RadioSpeaker.stopNoise();
        try {
          const pd2 = await _getPhoneData();
          const prog2 = (pd2.radioPrograms && pd2.radioPrograms[catId] || [])[idx];
          if (prog2) {
            // 备份关键状态：生成失败时回滚，避免一失败就把下期预告挪成本期、正文被清空（生成成功后清掉）
            prog2._updateBackup = {
              body: prog2._body || '',
              showName: prog2.showName || '',
              intro: prog2.intro || '',
              nextShow: prog2.nextShow || '',
              nextPreview: prog2.nextPreview || ''
            };
            // 把当前这期归档进历史节目（去重，最多保留 30 期）
            _radioArchiveEpisode(prog2);
            prog2._prevBody = prog2._body || '';   // 记下上一期正文，供续期生成时参考避重（生成成功后清掉）
            prog2._body = '';           // 清掉本期正文，触发重新生成新一期
            prog2._generating = false;
            // 更新单期标题：新闻类用 fixedNext.name（固定预告）；路况这类全天候滚动台用 staticShow（固定节目名/简介）；其它类用 nextShow（AI 上期输出的下期主题，或用户手填）
            const isNews = _radioIsNewsTag(prog2);
            const _staticTag = _radioStaticShowByTag((prog2.tags || [])[0]);
            if (isNews) {
              // 新闻类：从标签拿固定预告名，用户手动填了 nextShow 就用手动的
              const tag = (prog2.tags || [])[0];
              const fx = _radioFixedNextByTag(tag);
              prog2.showName = (prog2.nextShow || '').trim() || (fx && fx.name) || prog2.showName;
            } else if (_staticTag) {
              // 全天候滚动台（路况）：每期都用固定的节目名/简介，不依赖 AI 动态预告
              prog2.showName = _staticTag.name || prog2.showName;
              if (_staticTag.desc) prog2.intro = _staticTag.desc;
              prog2.nextShow = '';
              prog2.nextPreview = '';
            } else {
              // 非新闻类：上期 AI 输出的下期节目名/简介（存在 nextShow/nextPreview）就用；没有则清空，
              // 不沿用上一期标题/简介——让本期 AI 自己构思主题，并在结尾产出下期的 [[next:]] 供再下一期用
              prog2.showName = (prog2.nextShow || '').trim();
              // 简介兜底：上期 AI 偶尔会漏输出 [[next:]]（尤其连线收尾段），导致 nextPreview 为空。
              // 这时回退沿用上一期简介，而不是清空——避免归档进历史的 intro 为空、标题避重类续期列表退化成只有节目名。
              prog2.intro = (prog2.nextPreview || '').trim() || (prog2.intro || '').trim();
              // nextShow/nextPreview 已消费：清掉，由本期重新生成时再产出新的下期预告
              prog2.nextShow = '';
              prog2.nextPreview = '';
            }
            await _savePhoneData();
          }
        } catch (_) {}
        // 不带 showUpdateGate 重开：走标准 needGen 流程生成本期新内容；fromMine 保留以便返回回「我的」
        await _radioOpenDetail(catId, idx, { fromMine: true });
      };
    }
    // 进入详情页：未播态——隐藏气泡，显示中间提示
    _radioRevealInit(overlay);
    // 底部播放器：接系统/MiniMax TTS 朗读主播+嘉宾台词
    const playBtn = overlay.querySelector('#phone-radio-play');
    const spectrum = overlay.querySelector('#phone-radio-spectrum');

    // 异步生成正文：生成期间禁用播放键，完成后填入正文并解禁
    if (needGen) {
      if (playBtn) { playBtn.disabled = true; playBtn.style.opacity = '0.4'; playBtn.style.pointerEvents = 'none'; }
      (async () => {
        const body = await _radioGenProgramBody(p);
        // 详情页可能已被关闭：overlay 不在文档里就只持久化数据
        const stillOpen = document.body.contains(overlay);
        if (!body) {
          p._generating = false;
          // 续期更新失败：回滚到点更新前的状态，避免下期预告被挪成本期、正文被清空（生成失败累积破坏）
          if (p._updateBackup) {
            const bk = p._updateBackup;
            p._body = bk.body;
            p.showName = bk.showName;
            p.intro = bk.intro;
            p.nextShow = bk.nextShow;
            p.nextPreview = bk.nextPreview;
            delete p._updateBackup;
            if (p._prevBody) delete p._prevBody;
            try { await _savePhoneData(); } catch (_) {}
          }
          if (stillOpen) {
            const hintEl = overlay.querySelector('#phone-radio-detail-hint');
            if (hintEl) hintEl.textContent = '节目生成失败，请返回重试';
          }
          UI.showToast('节目生成失败，请重试', 1800);
          return;
        }
        p._body = body;
        p._generating = false;
        p._duration = _radioDurationOf(p);
        // 首次生成：提取正文末尾 AI 输出的下期预告元数据 [[next:名|简介]]，存进 nextShow/nextPreview 供续期与"我的"页预告显示
        try {
          const nx = _radioExtractNext(body);
          if (nx) {
            if (nx.name) p.nextShow = nx.name;
            if (nx.desc) p.nextPreview = nx.desc;
          }
        } catch (_) {}
        if (p._prevBody) delete p._prevBody; // 续期参考已用过，清掉避免下次正常生成时又带上一期
        if (p._updateBackup) delete p._updateBackup; // 续期成功：清掉回滚备份
        _radioArchiveEpisode(p); // 本期生成成功即归档进历史（去重），保证听过的每期都能在历史里回放
        try { await _radioPersistBody(catId, idx, -1, body); } catch (_) {}
        // 生成了详情正文的台 → 加入「我的」订阅
        try { await _radioSubscribeStation(catId, p); } catch (_) {}
        if (stillOpen) {
          const bodyEl = overlay.querySelector('.phone-radio-detail-body');
          if (bodyEl) bodyEl.innerHTML = _radioRenderSegments(body, p);
          const hintEl = overlay.querySelector('#phone-radio-detail-hint');
          if (hintEl) hintEl.textContent = '点击播放按钮开始';
          const syncWrap = overlay.querySelector('#phone-radio-detail-sync');
          if (syncWrap) syncWrap.style.display = (_radioIsNewsTag(p) && !_radioHasPendingInteract(body)) ? '' : 'none';
          _radioRevealInit(overlay);
          if (playBtn) { playBtn.disabled = false; playBtn.style.opacity = ''; playBtn.style.pointerEvents = ''; }
        }
      })();
    }

    if (playBtn) {
      // 留言生成成功后：替换锚点正文 → 重渲染 → 从锚点段之后续播
      // opts 可选：{ hideFromSeg, playFromSeg } —— 连线挂断用，让已显示的连线对话段保持可见、不重播
      const applyMailResult = (segIdx, newBody, opts) => {
        _radioPersistBody(catId, idx, -1, newBody);
        const hideFrom = (opts && typeof opts.hideFromSeg === 'number') ? opts.hideFromSeg : segIdx;
        const playFrom = (opts && typeof opts.playFromSeg === 'number') ? opts.playFromSeg : (segIdx - 1);
        const body = overlay.querySelector('.phone-radio-detail-body');
        if (body) {
          body.innerHTML = _radioRenderSegments(newBody, p);
          const allSegs = body.querySelectorAll('[data-seg-idx]');
          allSegs.forEach(el => {
            const i = parseInt(el.getAttribute('data-seg-idx'), 10);
            // hideFrom 及之后隐藏，随朗读浮现；之前的（含已显示的连线对话）保持可见
            if (i >= hideFrom) el.classList.add('seg-hidden');
          });
        }
        // 互动完成、正文已无 pending 锚点 → 显示"同步主线"按钮，并把这期完整正文归档进历史
        const syncBox = overlay.querySelector('#phone-radio-detail-sync');
        if (!_radioHasPendingInteract(newBody)) {
          if (syncBox && _radioIsNewsTag(p)) syncBox.style.display = '';
          // 互动后才生成玩法之后的内容，此时才是完整的一期 → 归档（去重）
          (async () => {
            try {
              const pd2 = await _getPhoneData();
              const prog2 = (pd2.radioPrograms && pd2.radioPrograms[catId] || [])[idx];
              if (prog2) { prog2._body = newBody; _radioArchiveEpisode(prog2); }
              // 内存里这份也归档，保证当前会话「我的」拷贝同步
              p._body = newBody; _radioArchiveEpisode(p);
              await _savePhoneData(pd2);
              try { await _radioSubscribeStation(catId, p); } catch (_) {}
            } catch (e) { console.warn('[互动后归档]', e); }
          })();
        }
        doPlay(playFrom);
      };
      // 续播：互动生成后从指定段之后继续；startSeg<0 表示从头
      var _interactPaused = false;
      var doPlay = (startSeg) => {
        _interactPaused = false;
        _radioRevealStart(overlay);
        _RadioSpeaker.start(p._body || bodyRaw, p, (playing) => {
          playBtn.innerHTML = _musicSvg(playing ? 'pauseBig' : 'playBig');
          if (spectrum) {
            if (playing) spectrum.classList.add('playing');
            else spectrum.classList.remove('playing');
          }
          // 只有真正结束（非互动暂停）才全显示
          if (!playing && !_interactPaused) _radioRevealAll(overlay);
        }, (segIdx) => {
          _radioRevealSeg(overlay, segIdx);
        }, () => {
          // 一期自然播完：先记一条收听日志（同步主线，受全局开关控制，本轮按期去重）
          _radioLogListen(p, catId, false);
          // 若有待播点歌，先关底噪放歌并跳过循环；否则按循环模式决定下一步
          if (p._pendingSongId) { _radioMaybePlaySong(p); return; }
          if (_radioRepeatMode === 'one') {
            setTimeout(() => { if (playBtn && !_RadioSpeaker.isSpeaking()) doPlay(-1); }, 600);
          }
        }, {
          startSeg: (typeof startSeg === 'number' ? startSeg : -1),
          onInteract: (segIdx, type) => {
            // 互动暂停态：标记（不触发 revealAll），停播放+频谱
            _interactPaused = true;
            playBtn.innerHTML = _musicSvg('playBig');
            if (spectrum) spectrum.classList.remove('playing');
            // 让互动卡片浮现并滚到中央
            _radioRevealSeg(overlay, segIdx);
          }
        });
      };
      playBtn.onclick = () => {
        if (_RadioSpeaker.isSpeaking()) {
          _RadioSpeaker.stop();
          _interactPaused = false;
          playBtn.innerHTML = _musicSvg('playBig');
          if (spectrum) spectrum.classList.remove('playing');
          _radioRevealAll(overlay);
          return;
        }
        doPlay(-1);
      };
      // 互动卡片按钮：不留言 / 我要留言 / 投票选项（事件委托）
      const bodyEl = overlay.querySelector('.phone-radio-detail-body');
      if (bodyEl) {
        bodyEl.addEventListener('click', (e) => {
          const ibtn = e.target.closest && e.target.closest('.phone-radio-interact-btn, .phone-radio-vote-opt');
          if (!ibtn || ibtn.disabled) return;
          const card = ibtn.closest('.phone-radio-interact');
          const segIdx = card ? parseInt(card.getAttribute('data-seg-idx'), 10) : -1;
          const playId = card ? (card.getAttribute('data-interact') || 'mail') : 'mail';
          const play = _radioPlayById(playId) || _RADIO_PLAYS.mail;
          const act = ibtn.getAttribute('data-act');
          if (_RadioSpeaker.isSpeaking()) _RadioSpeaker.stop();
          if (act === 'skip') {
            // 不参与：照样生成一段（纯虚拟听众/纯随机投票）+ 收尾，标记为 done（行为同参与，只是没有玩家输入）
            _radioHandlePlay(play, overlay, p, { catId, idx, histIdx: -1 }, (newBody, opts) => {
              applyMailResult(segIdx, newBody, opts);
            }, { skip: true });
            return;
          }
          if (act === 'vote') {
            // 投票：玩家点了某个选项，取选项索引 + 该锚点的问题/选项列表
            const optIdx = parseInt(ibtn.getAttribute('data-opt'), 10);
            const segs = _parseRadioReply(p._body || '');
            const seg = segs[segIdx];
            const params = (seg && Array.isArray(seg.params)) ? seg.params : [];
            _radioHandlePlay(play, overlay, p, { catId, idx, histIdx: -1 }, (newBody, opts) => {
              applyMailResult(segIdx, newBody, opts);
            }, { vote: { optIdx, question: params[0] || '', options: params.slice(1) } });
            return;
          }
          // 参与玩法（mail 的"我要留言"、lottery 的"参与抽奖"）：分发到对应 handler
          if (act === 'play') {
            // 抽奖玩法：弹窗输入姓名
            if (playId === 'lottery') {
              const segs = _parseRadioReply(p._body || '');
              const seg = segs[segIdx];
              const params = (seg && Array.isArray(seg.params)) ? seg.params : [];
              const prizeName = params[0] || '神秘礼物';
              _radioLotteryInput(prizeName).then(result => {
                if (!result) return; // 取消
                _radioHandlePlay(play, overlay, p, { catId, idx, histIdx: -1 }, (newBody, opts) => {
                  applyMailResult(segIdx, newBody, opts);
                }, { lottery: { name: result.name, prizeName } });
              });
              return;
            }
            // 问卜玩法：弹窗填写名字/所问/额外信息
            if (playId === 'divination') {
              _radioDivinationInput().then(result => {
                if (!result) return; // 取消
                _radioHandlePlay(play, overlay, p, { catId, idx, histIdx: -1 }, (newBody, opts) => {
                  applyMailResult(segIdx, newBody, opts);
                }, { divination: result });
              });
              return;
            }
            // 其他玩法（mail/call等）：直接分发
            _radioHandlePlay(play, overlay, p, { catId, idx, histIdx: -1 }, (newBody, opts) => {
              applyMailResult(segIdx, newBody, opts);
            });
          }
        });
      }
    }
  }

  // ===== 电台设置页（整页 overlay，两 tab：电台信息 / 历史节目）=====
  // 历史存档时间格式化：MM-DD HH:mm（现实时间，非游戏内历法）
  function _radioFmtArchiveTime(d) {
    try {
      const dt = (d instanceof Date) ? d : new Date(d);
      if (isNaN(dt.getTime())) return '';
      const mm = String(dt.getMonth() + 1).padStart(2, '0');
      const dd = String(dt.getDate()).padStart(2, '0');
      const hh = String(dt.getHours()).padStart(2, '0');
      const mi = String(dt.getMinutes()).padStart(2, '0');
      return `${mm}-${dd} ${hh}:${mi}`;
    } catch (_) { return ''; }
  }
  // 获取系统可用嗓音（优先中文）
  function _radioGetSystemVoices() {
    try {
      if (!('speechSynthesis' in window)) return [];
      const all = window.speechSynthesis.getVoices() || [];
      const zh = all.filter(v => /zh|cmn|chinese/i.test(v.lang || ''));
      return (zh.length ? zh : all);
    } catch (_) { return []; }
  }

  // 预热系统嗓音（嗓音异步加载，首次 getVoices 常为空；Edge 需轮询）
  function _radioWarmSystemVoices(timeoutMs = 3000) {
    return new Promise((resolve) => {
      try {
        if (!('speechSynthesis' in window)) { resolve([]); return; }
        let done = false;
        let timer = null;
        const finish = () => {
          if (done) return;
          done = true;
          try { window.speechSynthesis.onvoiceschanged = null; } catch (_) {}
          if (timer) clearInterval(timer);
          resolve(_radioGetSystemVoices());
        };
        const now = window.speechSynthesis.getVoices() || [];
        if (now.length) { finish(); return; }
        window.speechSynthesis.onvoiceschanged = () => {
          if ((window.speechSynthesis.getVoices() || []).length) finish();
        };
        const start = Date.now();
        timer = setInterval(() => {
          if ((window.speechSynthesis.getVoices() || []).length) { finish(); return; }
          if (Date.now() - start > timeoutMs) finish();
        }, 200);
      } catch (_) { resolve([]); }
    });
  }

  // 渲染单个角色（主播/嘉宾）的引擎切换 + 音色选择
  function _radioRoleVoiceHtml(role, roleVoice) {
    const engine = roleVoice.engine === 'minimax' ? 'minimax' : 'system';
    const label = role === 'dj' ? '主播' : '嘉宾';
    const engineTabs = `
      <div class="phone-radio-engine-tabs">
        <button type="button" class="phone-radio-engine-tab${engine !== 'minimax' ? ' active' : ''}" data-role="${role}" data-engine="system">系统 TTS</button>
        <button type="button" class="phone-radio-engine-tab${engine === 'minimax' ? ' active' : ''}" data-role="${role}" data-engine="minimax">MiniMax</button>
      </div>`;
    let picker;
    if (engine === 'system') {
      const voices = _radioGetSystemVoices();
      const opts = `<option value="">默认音色</option>` + voices.map(v =>
        `<option value="${Utils.escapeHtml(v.voiceURI || v.name)}" ${roleVoice.voice === (v.voiceURI || v.name) ? 'selected' : ''}>${Utils.escapeHtml(v.name)}（${Utils.escapeHtml(v.lang || '')}）</option>`
      ).join('');
      const hint = voices.length ? '' : `<div class="phone-radio-set-tip" style="margin-top:6px">系统语音加载中或未检测到，<a href="javascript:void(0)" class="phone-radio-voice-retry" style="color:var(--accent)">点此重新检测</a>。</div>`;
      picker = `<select class="phone-radio-voice-pick" data-role="${role}">${opts}</select>${hint}`;
    } else {
      picker = `<input type="text" class="phone-radio-voice-pick" data-role="${role}" value="${Utils.escapeHtml(roleVoice.voice || '')}" placeholder="MiniMax 音色 ID，如 male-qn-qingse">`;
    }
    return `
      <div class="phone-radio-role-block" data-role-block="${role}">
        <div class="phone-radio-role-title">${label}音色</div>
        ${engineTabs}
        <div class="phone-radio-role-picker" data-role-picker="${role}">${picker}</div>
      </div>`;
  }

  // 渲染主播+嘉宾两个区块
  function _radioVoicePickersHtml(voice) {
    const hasMinimax = (voice.dj.engine === 'minimax' || voice.guest.engine === 'minimax');
    const mmTip = hasMinimax ? `<div class="phone-radio-set-tip" style="margin-top:8px">MiniMax 音色需在「设置 → 功能模型 → 语音模型」配置 API Key。</div>` : '';
    return _radioRoleVoiceHtml('dj', voice.dj) + _radioRoleVoiceHtml('guest', voice.guest) + mmTip;
  }

  // 绑定"重新检测系统嗓音"链接（可能在多个角色区块里出现）
  function _bindVoiceRetry(overlay, p) {
    overlay.querySelectorAll('.phone-radio-voice-retry').forEach(link => {
      link.onclick = async (e) => {
        e.preventDefault();
        link.textContent = '检测中…';
        await _radioWarmSystemVoices(3000);
        const pickers = overlay.querySelector('#phone-radio-voice-pickers');
        if (pickers) pickers.innerHTML = _radioVoicePickersHtml(p.voice);
        // 重绑引擎 tab
        overlay.querySelectorAll('.phone-radio-engine-tab').forEach(tab => {
          const role = tab.getAttribute('data-role');
          const eng = tab.getAttribute('data-engine');
          tab.onclick = () => {
            if (!role || eng === p.voice[role].engine) return;
            p.voice[role].engine = eng;
            p.voice[role].voice = '';
            const block = overlay.querySelector(`[data-role-block="${role}"]`);
            if (block) {
              block.innerHTML = _radioRoleVoiceHtml(role, p.voice[role]);
              block.querySelectorAll('.phone-radio-engine-tab').forEach(t => { t.onclick = tab.onclick; });
            }
          };
        });
        _bindVoiceRetry(overlay, p);
      };
    });
  }

  async function _radioOpenSettings(catId, idx) {
    const pd = await _getPhoneData();
    const programs = (pd.radioPrograms && pd.radioPrograms[catId]) || [];
    const p = programs[idx];
    if (!p) { UI.showToast('节目不存在', 1500); return; }

    // 历史节目：只收录真实归档（"收听本期更新"时把上一期推进 history）。无则空，页面显示空态提示。
    if (!Array.isArray(p.history)) {
      p.history = [];
    }

    if (!p.voice || typeof p.voice !== 'object') {
      p.voice = { enabled: false, dj: { engine: 'system', voice: '' }, guest: { engine: 'system', voice: '' } };
    }
    // 兼容旧结构（engine/dj/guest 为字符串的扁平版）→ 升级为按角色独立
    if (typeof p.voice.dj !== 'object' || p.voice.dj === null) {
      const oldEngine = p.voice.engine === 'minimax' ? 'minimax' : 'system';
      p.voice = {
        enabled: !!p.voice.enabled,
        dj: { engine: oldEngine, voice: typeof p.voice.dj === 'string' ? p.voice.dj : '' },
        guest: { engine: oldEngine, voice: typeof p.voice.guest === 'string' ? p.voice.guest : '' }
      };
    }

    const overlay = document.createElement('div');
    overlay.className = 'phone-radio-detail phone-radio-settings';

    const renderInfoTab = () => {
      const coverStyle = p.cover ? `background-image:url('${p.cover}')` : '';
      return `
        <div class="phone-radio-set-section">
          <div class="phone-radio-set-cover" id="phone-radio-set-cover" style="${coverStyle}">
            ${p.cover ? '' : `<div class="phone-radio-set-cover-ph">${_uiIcon('image', 28)}<span>设置封面</span></div>`}
            <div class="phone-radio-set-cover-edit">${_uiIcon('camera', 16)}</div>
          </div>
        </div>
        <div class="phone-radio-set-field">
          <label>电台名</label>
          <input type="text" id="phone-radio-set-name" maxlength="12" value="${Utils.escapeHtml(p.name || '')}" placeholder="电台名称">
        </div>
        <div class="phone-radio-set-field">
          <label>核心概念</label>
          <textarea id="phone-radio-set-concept" rows="5" placeholder="这档节目的风格定位、内容方向、主播人设、目标受众…">${Utils.escapeHtml(p.concept || '')}</textarea>
        </div>
        <div class="phone-radio-set-field-row">
          <div class="phone-radio-set-field">
            <label>主播</label>
            <input type="text" id="phone-radio-set-dj" maxlength="8" value="${Utils.escapeHtml(p.dj || '')}" placeholder="主播名">
          </div>
          <div class="phone-radio-set-field">
            <label>嘉宾<span class="phone-radio-set-hint">（可空）</span></label>
            <input type="text" id="phone-radio-set-guest" maxlength="8" value="${Utils.escapeHtml(p.guest || '')}" placeholder="嘉宾名">
          </div>
        </div>
        <div class="phone-radio-set-field">
          <label>本期节目</label>
          <input type="text" id="phone-radio-set-showname" maxlength="30" value="${Utils.escapeHtml(p.showName || '')}" placeholder="本期节目名">
        </div>
        <div class="phone-radio-set-field">
          <label>节目简介</label>
          <textarea id="phone-radio-set-intro" rows="2" placeholder="一句话介绍这期节目">${Utils.escapeHtml(p.intro || '')}</textarea>
        </div>
        <div class="phone-radio-set-field">
          <label>下期节目</label>
          <input type="text" id="phone-radio-set-nextshow" maxlength="30" value="${Utils.escapeHtml(p.nextShow || '')}" placeholder="下期节目名">
        </div>
        <div class="phone-radio-set-field">
          <label>下期预告</label>
          <textarea id="phone-radio-set-nextpreview" rows="2" placeholder="预告一下下期内容">${Utils.escapeHtml(p.nextPreview || '')}</textarea>
        </div>
        <div class="phone-radio-set-tip">已经生成过的内容不会改动，这里的修改将在下次调频生成时生效。</div>
        <div class="phone-radio-set-voice">
          <div class="phone-radio-set-voice-head">
            <span>启用语音朗读</span>
            <label class="phone-radio-switch">
              <input type="checkbox" id="phone-radio-voice-toggle" ${p.voice.enabled ? 'checked' : ''}>
              <span class="phone-radio-switch-slider"></span>
            </label>
          </div>
          <div class="phone-radio-set-voice-body" id="phone-radio-voice-body" style="display:${p.voice.enabled ? 'block' : 'none'}">
            <div id="phone-radio-voice-pickers">${_radioVoicePickersHtml(p.voice)}</div>
          </div>
        </div>
        <button class="phone-radio-set-save" id="phone-radio-set-save">保存设置</button>`;
    };

    const renderHistTab = () => {
      const list = p.history || [];
      if (!list.length) {
        return `<div class="phone-radio-hist-empty">还没有历史节目，调频生成后会自动存档。</div>`;
      }
      return `<div class="phone-radio-hist-list">${list.map((h, i) => {
        const cover = h.cover ? `<div class="phone-radio-hist-cover" style="background-image:url('${h.cover.replace(/'/g, '')}')"></div>` : `<div class="phone-radio-hist-cover phone-radio-hist-cover-ph">${_radioChannelSvg('mic')}</div>`;
        const tags = (h.tags || []).slice(0, 2).map(t => `<span class="phone-radio-hist-tag">${Utils.escapeHtml(t)}</span>`).join('');
        return `<div class="phone-radio-hist-item" data-hist="${i}">
          ${cover}
          <div class="phone-radio-hist-info">
            <div class="phone-radio-hist-name">${Utils.escapeHtml(h.showName || '本期节目')}</div>
            <div class="phone-radio-hist-meta">${Utils.escapeHtml(_radioDisplayName(h.dj) || '')}${h.guest ? ' · ' + Utils.escapeHtml(_radioDisplayName(h.guest)) : ''} · ${Utils.escapeHtml(h.duration || '')}</div>
            <div class="phone-radio-hist-tags">${tags}<span class="phone-radio-hist-time">${Utils.escapeHtml(/\dT\d|Z$/.test(h.time || '') ? _radioFmtArchiveTime(h.time) : (h.time || ''))}</span></div>
          </div>
          <div class="phone-radio-hist-play">${_musicSvg('playBig')}</div>
        </div>`;
      }).join('')}</div>`;
    };

    overlay.innerHTML = `
      <div class="phone-radio-detail-head">
        <button class="phone-radio-detail-back" id="phone-radio-set-back">
          <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 12H5"/><path d="m12 5-7 7 7 7"/></svg>
        </button>
        <div class="phone-radio-detail-headinfo">
          <div class="phone-radio-detail-name">电台设置</div>
        </div>
      </div>
      <div class="phone-radio-set-tabs">
        <button class="phone-radio-set-tab active" data-tab="info">电台信息</button>
        <button class="phone-radio-set-tab" data-tab="hist">历史节目</button>
      </div>
      <div class="phone-radio-detail-scroll" id="phone-radio-set-body">
        ${renderInfoTab()}
      </div>`;

    const shell = document.querySelector('#phone-modal .phone-shell') || document.body;
    shell.appendChild(overlay);

    const back = overlay.querySelector('#phone-radio-set-back');
    if (back) back.onclick = () => overlay.remove();

    const bodyEl = overlay.querySelector('#phone-radio-set-body');
    const tabs = overlay.querySelectorAll('.phone-radio-set-tab');
    let curTab = 'info';

    const bindInfoEvents = () => {
      const coverEl = overlay.querySelector('#phone-radio-set-cover');
      if (coverEl) coverEl.onclick = async () => {
        try {
          const dataUrl = await Utils.promptImageInput({ maxSize: 600, quality: 0.82 });
          if (!dataUrl) return;
          if (typeof dataUrl === 'string' && dataUrl.length > 2600000) {
            UI.showToast('图片过大，请选择更小的图片', 2500); return;
          }
          p.cover = dataUrl;
          coverEl.style.backgroundImage = `url('${dataUrl}')`;
          const ph = coverEl.querySelector('.phone-radio-set-cover-ph');
          if (ph) ph.remove();
        } catch (e) { console.warn('[Radio] cover pick failed', e); UI.showToast('图片处理失败', 1500); }
      };
      // 语音朗读开关
      const vToggle = overlay.querySelector('#phone-radio-voice-toggle');
      const vBody = overlay.querySelector('#phone-radio-voice-body');
      if (vToggle && vBody) {
        vToggle.onchange = () => {
          p.voice.enabled = vToggle.checked;
          vBody.style.display = vToggle.checked ? 'block' : 'none';
        };
      }
      // 引擎切换：按角色独立切换
      overlay.querySelectorAll('.phone-radio-engine-tab').forEach(tab => {
        tab.onclick = () => {
          const role = tab.getAttribute('data-role');
          const eng = tab.getAttribute('data-engine');
          if (!role || eng === p.voice[role].engine) return;
          p.voice[role].engine = eng;
          p.voice[role].voice = '';
          const block = overlay.querySelector(`[data-role-block="${role}"]`);
          if (block) {
            block.innerHTML = _radioRoleVoiceHtml(role, p.voice[role]);
            // 重绑新 block 内的引擎 tab
            block.querySelectorAll('.phone-radio-engine-tab').forEach(t => { t.onclick = tab.onclick; });
          }
        };
      });
      // 手动重新检测系统嗓音
      _bindVoiceRetry(overlay, p);
      const saveBtn = overlay.querySelector('#phone-radio-set-save');
      if (saveBtn) saveBtn.onclick = async () => {
        const name = (overlay.querySelector('#phone-radio-set-name')?.value || '').trim();
        const concept = (overlay.querySelector('#phone-radio-set-concept')?.value || '').trim();
        const dj = (overlay.querySelector('#phone-radio-set-dj')?.value || '').trim();
        const guest = (overlay.querySelector('#phone-radio-set-guest')?.value || '').trim();
        if (name) p.name = name.slice(0, 12);
        p.concept = concept;
        p.showName = (overlay.querySelector('#phone-radio-set-showname')?.value || '').trim().slice(0, 30);
        p.intro = (overlay.querySelector('#phone-radio-set-intro')?.value || '').trim().slice(0, 80);
        p.nextShow = (overlay.querySelector('#phone-radio-set-nextshow')?.value || '').trim().slice(0, 30);
        p.nextPreview = (overlay.querySelector('#phone-radio-set-nextpreview')?.value || '').trim().slice(0, 80);
        p.dj = dj.slice(0, 8) || '匿名';
        p.guest = guest.slice(0, 8);
        // 语音设置
      p.voice.enabled = !!(overlay.querySelector('#phone-radio-voice-toggle')?.checked);
      ['dj', 'guest'].forEach(role => {
          const pick = overlay.querySelector(`.phone-radio-voice-pick[data-role="${role}"]`);
          if (pick) p.voice[role].voice = (pick.value || '').trim();
        });
        await _savePhoneData();
        UI.showToast('已保存，将在下期生成时生效', 1800);
        overlay.remove();
      };
    };

    const bindHistEvents = () => {
      overlay.querySelectorAll('.phone-radio-hist-item').forEach(el => {
        el.onclick = () => {
          const hi = parseInt(el.getAttribute('data-hist'), 10);
          _radioPlayHistory(catId, idx, hi);
        };
      });
    };

    bindInfoEvents();
    // 异步预热系统嗓音：首次 getVoices 为空时，等 voiceschanged 再刷新选择器
    _radioWarmSystemVoices().then(voices => {
        if (voices.length && curTab === 'info') {
          const pickers = overlay.querySelector('#phone-radio-voice-pickers');
          if (pickers) pickers.innerHTML = _radioVoicePickersHtml(p.voice);
        }
    });

    tabs.forEach(tab => {
      tab.onclick = () => {
        const t = tab.getAttribute('data-tab');
        if (t === curTab) return;
        curTab = t;
        tabs.forEach(x => x.classList.toggle('active', x === tab));
        bodyEl.innerHTML = t === 'info' ? renderInfoTab() : renderHistTab();
        if (t === 'info') bindInfoEvents(); else bindHistEvents();
      };
    });
  }

  // 回放历史节目：用存档正文打开详情页
  async function _radioPlayHistory(catId, idx, histIdx) {
    const pd = await _getPhoneData();
    _radioRefreshGlobalPrefsCache(pd);
    const programs = (pd.radioPrograms && pd.radioPrograms[catId]) || [];
    const p = programs[idx];
    if (!p) { UI.showToast('节目不存在', 1500); return; }
    const h = (p.history || [])[histIdx];
    if (!h) { UI.showToast('历史节目不存在', 1500); return; }
    const snapshot = Object.assign({}, p, {
      showName: h.title || h.showName || p.showName,  // 优先用 title（新归档），回退 showName（老数据）
      dj: h.dj || p.dj,
      guest: h.guest || p.guest,
      tags: h.tags || p.tags,
      cover: h.cover || p.cover,
      _body: h.body || _RADIO_FAKE_BODY,
      _duration: h.duration || _radioDurationOf({ tags: h.tags || p.tags })
    });
    _radioOpenDetailWith(snapshot, { catId, idx, histIdx, total: (p.history || []).length });
  }

  // 电台节目分享：把当前期正文拼成一张图导出
  async function _radioShareProgram(prog) {
    if (!prog || !prog._body) { UI.showToast('节目尚未生成', 1500); return; }
    if (typeof html2canvas === 'undefined') { UI.showToast('截图库未加载', 2000); return; }
    const ok = await UI.showConfirm('生成分享截图', '即将把本期节目正文拼成一张长图，内容较长时需要花费几秒钟，是否继续？');
    if (!ok) return;
    UI.showToast('正在生成截图…', 2500);

    const showName = prog.showName || prog.name || '本期节目';
    const stationName = prog.name || '电台';
    const fmText = prog.fm ? `FM ${prog.fm}` : '';
    const djName = _radioDisplayName(prog.dj) || '匿名';
    const guestName = prog.guest ? _radioDisplayName(prog.guest) : '';
    const hostLine = `主播 ${djName}${guestName ? ` · 嘉宾 ${guestName}` : ''}`;
    const duration = prog._duration || _radioDurationOf(prog);
    const tagsHtml = (prog.tags || []).map(t =>
      `<span style="font-size:10px;padding:2px 9px;border-radius:999px;background:rgba(124,92,200,0.12);color:#7c5cc8">${Utils.escapeHtml(t)}</span>`
    ).join(' ');

    // 封面圆图
    const coverImg = (prog.cover || '').trim();
    const avatarHtml = coverImg
      ? `<img src="${coverImg}" style="width:56px;height:56px;object-fit:cover;border-radius:50%">`
      : `<div style="width:56px;height:56px;border-radius:50%;background:rgba(124,92,200,0.12);display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:700;color:#7c5cc8">${Utils.escapeHtml((stationName || '电')[0])}</div>`;

    // 解析正文，渲染成段落（叙述行=居中灰字小卡；主播/嘉宾/来电=气泡；玩法锚点跳过）
    const segs = _parseRadioReply(prog._body);
    let djSpeaker = '';
    const firstLine = segs.find(s => s.kind !== 'desc' && s.speaker);
    if (firstLine) djSpeaker = firstLine.speaker;
    if (!djSpeaker) djSpeaker = prog.dj || '';

    const bodyHtml = segs.map(seg => {
      if (!seg.text) return '';
      if (seg.kind === 'interact') return ''; // 玩法卡片不进分享图
      if (seg.kind === 'desc') {
        return `<div style="text-align:center;font-size:11px;color:#aaa;font-style:italic;margin:10px auto;max-width:90%;line-height:1.6">${Utils.escapeHtml(seg.text)}</div>`;
      }
      if (seg.kind === 'callme') {
        // 玩家连线发言：右对齐高亮气泡
        return `<div style="display:flex;justify-content:flex-end;margin:6px 0"><div style="max-width:78%;background:#7c5cc8;color:#fff;font-size:12.5px;line-height:1.6;padding:8px 12px;border-radius:14px 14px 4px 14px">${Utils.escapeHtml(seg.text)}</div></div>`;
      }
      // line / caller：说话人名 + 气泡
      const isHost = !seg.speaker || seg.speaker === djSpeaker;
      const name = seg.speaker || djSpeaker || '主播';
      const bubbleBg = isHost ? 'rgba(124,92,200,0.08)' : 'rgba(0,0,0,0.04)';
      const nameColor = isHost ? '#7c5cc8' : '#888';
      return `<div style="margin:7px 0">
        <div style="font-size:10px;font-weight:600;color:${nameColor};margin-bottom:3px">${Utils.escapeHtml(name)}</div>
        <div style="background:${bubbleBg};font-size:12.5px;color:#333;line-height:1.65;padding:8px 12px;border-radius:4px 14px 14px 14px">${Utils.escapeHtml(seg.text)}</div>
      </div>`;
    }).join('');

    // 构建截图容器
    const temp = document.createElement('div');
    temp.style.cssText = 'position:fixed;top:0;left:-10000px;width:400px;padding:24px;background:#fff;border-radius:20px;box-sizing:border-box;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif';
    temp.innerHTML = `
      <div style="display:flex;align-items:center;gap:14px;margin-bottom:16px">
        ${avatarHtml}
        <div style="flex:1;min-width:0">
          <div style="font-size:13px;color:#999">${Utils.escapeHtml(stationName)}${fmText ? ` · ${Utils.escapeHtml(fmText)}` : ''}</div>
          <div style="font-size:18px;font-weight:700;color:#222;margin-top:2px;line-height:1.3">${Utils.escapeHtml(showName)}</div>
        </div>
      </div>
      <div style="display:flex;flex-wrap:wrap;align-items:center;gap:6px;margin-bottom:6px">${tagsHtml}</div>
      <div style="font-size:11px;color:#999;margin-bottom:16px;padding-bottom:14px;border-bottom:1px solid #f0f0f0">${Utils.escapeHtml(hostLine)} · ⏱ ${Utils.escapeHtml(duration)}</div>
      <div>${bodyHtml}</div>
      <div style="text-align:center;font-size:10px;color:#ccc;margin-top:18px;padding-top:12px;border-top:1px dashed #eee">— SKYNEX · 电台 —</div>
    `;
    document.body.appendChild(temp);

    try {
      const canvas = await html2canvas(temp, {
        backgroundColor: '#fff',
        useCORS: true,
        scale: 2,
        logging: false
      });
      const dataUrl = canvas.toDataURL('image/png');
      const a = document.createElement('a');
      a.href = dataUrl;
      a.download = `radio-${Date.now()}.png`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      UI.showToast('截图已导出', 2000);
    } catch (e) {
      console.error('[Radio-Share]', e);
      UI.showToast('截图失败：' + (e.message || '未知错误'), 3000);
    } finally {
      document.body.removeChild(temp);
    }
  }

  // 用给定 program 快照渲染详情页（回放专用，不依赖 catId/idx 取数据）
  function _radioOpenDetailWith(p, ctx) {
    ctx = ctx || {};
    const avatarHtml = p.cover
      ? `<img src="${Utils.escapeHtml(p.cover)}" alt="">`
      : `<div class="phone-radio-detail-avatar-fallback">${Utils.escapeHtml((p.name || '电')[0])}</div>`;
    const fmText = p.fm ? `FM ${Utils.escapeHtml(String(p.fm))}` : '';
    const tags = (p.tags || []).map(t => `<span class="phone-radio-card-tag">${Utils.escapeHtml(t)}</span>`).join('');
    const hostLine = `主播 ${Utils.escapeHtml(_radioDisplayName(p.dj) || '匿名')}${p.guest ? ` · 嘉宾 ${Utils.escapeHtml(_radioDisplayName(p.guest))}` : ''}`;
    const segHtml = _radioRenderSegments(p._body || _RADIO_FAKE_BODY, p);
    const duration = p._duration || _radioDurationOf(p);

    const overlay = document.createElement('div');
    overlay.className = 'phone-radio-detail';
    overlay.innerHTML = `
      <div class="phone-radio-detail-head">
        <button class="phone-radio-detail-back" id="phone-radio-hplay-back">
          <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 12H5"/><path d="m12 5-7 7 7 7"/></svg>
        </button>
        <div class="phone-radio-detail-headinfo">
          <div class="phone-radio-detail-name">${Utils.escapeHtml(p.name || '电台')}</div>
          <div class="phone-radio-detail-fm">${fmText}</div>
        </div>
        <div class="phone-radio-detail-avatar">${avatarHtml}</div>
      </div>
      <div class="phone-radio-detail-meta">
        <div class="phone-radio-detail-show">${Utils.escapeHtml(p.showName || '本期节目')}</div>
        <div class="phone-radio-detail-info-row">
          <span class="phone-radio-detail-tags">${tags}</span>
          <span class="phone-radio-detail-host">${hostLine}</span>
          <span class="phone-radio-detail-dur">⏱ ${Utils.escapeHtml(duration)}</span>
        </div>
      </div>
      <div class="phone-radio-detail-scroll">
        <div class="phone-radio-detail-hint" id="phone-radio-hplay-hint">点击播放按钮开始</div>
        <div class="phone-radio-detail-body">${segHtml}</div>
        <div class="phone-radio-detail-end">— 本期节目结束 —</div>
      </div>
      <div class="phone-radio-detail-player">
        <div class="phone-radio-player-progress">
          <div class="phone-radio-spectrum" id="phone-radio-hplay-spectrum">${_radioSpectrumBars(40)}</div>
        </div>
        <div class="phone-radio-player-controls">
          <button class="phone-mdetail-ctrl" id="phone-radio-hplay-skip">${_musicSvg('skipDown')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-hplay-prev">${_musicSvg('prev')}</button>
          <button class="phone-mdetail-ctrl phone-mdetail-play" id="phone-radio-hplay-play">${_musicSvg('playBig')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-hplay-next">${_musicSvg('nextTrack')}</button>
          <button class="phone-mdetail-ctrl" id="phone-radio-hplay-share" title="分享本期">${_uiIcon('share', 22)}</button>
        </div>
      </div>`;
    const shell = document.querySelector('#phone-modal .phone-shell') || document.body;
    shell.appendChild(overlay);
    const back = overlay.querySelector('#phone-radio-hplay-back');
    if (back) back.onclick = async () => {
      _RadioSpeaker.stop(); _RadioSpeaker.stopNoise(); _radioClearScare(); overlay.remove();
      // 从「我的」回放下架台进来的：返回时刷新「我的」列表
      if (ctx.fromMine) {
        try { _radioHomeTab = 'mine'; _renderRadio(await _getPhoneData()); } catch (_) {}
      }
    };
    if (_radioGlobalPrefsCache.noise) _RadioSpeaker.startNoise();
    // 怪谈类：启动随机惊吓特效计时
    _radioScheduleScare(overlay, p);
    const playBtn = overlay.querySelector('#phone-radio-hplay-play');
    const spectrum = overlay.querySelector('#phone-radio-hplay-spectrum');
    // 进入回放页：未播态——隐藏气泡，显示中间提示
    _radioRevealInit(overlay);
    // 切到指定历史期
    const switchTo = (hi) => {
      if (typeof ctx.catId === 'undefined') return;
      _RadioSpeaker.stop();
      _RadioSpeaker.stopNoise();
      _radioClearScare();
      overlay.remove();
      _radioPlayHistory(ctx.catId, ctx.idx, hi);
    };
    // 上一条 / 下一条
    const prevBtn = overlay.querySelector('#phone-radio-hplay-prev');
    const nextBtn = overlay.querySelector('#phone-radio-hplay-next');
    const total = ctx.total || 0;
    if (prevBtn) prevBtn.onclick = () => {
      if (typeof ctx.histIdx !== 'number' || total <= 1) { UI.showToast('没有上一期', 1200); return; }
      const hi = (ctx.histIdx - 1 + total) % total;
      switchTo(hi);
    };
    if (nextBtn) nextBtn.onclick = () => {
      if (typeof ctx.histIdx !== 'number' || total <= 1) { UI.showToast('没有下一期', 1200); return; }
      const hi = (ctx.histIdx + 1) % total;
      switchTo(hi);
    };
    // 分享：把当前正在看的这一期历史正文拼成一张图导出
    const shareBtn = overlay.querySelector('#phone-radio-hplay-share');
    if (shareBtn) shareBtn.onclick = () => _radioShareProgram(p);
    // 跳过动画：停止逐句朗读/推进，一次性显示全部内容
    const skipBtn = overlay.querySelector('#phone-radio-hplay-skip');
    if (skipBtn) skipBtn.onclick = () => {
      if (_RadioSpeaker.isSpeaking()) _RadioSpeaker.stop();
      if (playBtn) playBtn.innerHTML = _musicSvg('playBig');
      if (spectrum) spectrum.classList.remove('playing');
      _radioRevealAll(overlay);
    };
    if (playBtn) {
      playBtn.onclick = () => {
        if (_RadioSpeaker.isSpeaking()) {
          _RadioSpeaker.stop();
          playBtn.innerHTML = _musicSvg('playBig');
          if (spectrum) spectrum.classList.remove('playing');
          _radioRevealAll(overlay);
          return;
        }
        _radioRevealStart(overlay);
        _RadioSpeaker.start(p._body || _RADIO_FAKE_BODY, p, (playing) => {
          playBtn.innerHTML = _musicSvg(playing ? 'pauseBig' : 'playBig');
          if (spectrum) {
            if (playing) spectrum.classList.add('playing');
            else spectrum.classList.remove('playing');
          }
          if (!playing) _radioRevealAll(overlay);
        }, (segIdx) => {
          _radioRevealSeg(overlay, segIdx);
         }, () => {
           // 一期自然播完：先记一条"重温旧节目"日志（同步主线，受全局开关控制，本轮按期去重）
           _radioLogListen(p, ctx.catId, true);
           // 若有待播点歌，先关底噪放歌并跳过循环；否则按循环模式决定下一步
           if (p._pendingSongId) { _radioMaybePlaySong(p); return; }
           if (_radioRepeatMode === 'one') {
             // 单期循环：重播当前期
             setTimeout(() => { if (playBtn) playBtn.onclick(); }, 600);
           } else if (total > 1 && typeof ctx.histIdx === 'number') {
            // 列表循环：切下一期
            const hi = (ctx.histIdx + 1) % total;
            setTimeout(() => switchTo(hi), 600);
          }
        });
      };
    }
  }

  // 留言信封 SVG 图标
  function _radioMailSvg() {
    return '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px"><rect x="2" y="4" width="20" height="16" rx="2"/><path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/></svg>';
  }
  // 投票 SVG 图标（柱状图）
  function _radioVoteSvg() {
    return '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px"><line x1="6" x2="6" y1="20" y2="12"/><line x1="12" x2="12" y1="20" y2="4"/><line x1="18" x2="18" y1="20" y2="14"/></svg>';
  }
  // 点歌 SVG 图标（音符）
  function _radioRequestSvg() {
    return '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>';
  }
  // 问卜 SVG 图标（月与星·玄学意象）
  function _radioDivinationSvg() {
    return '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px"><path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z"/><path d="m17 3 .7 1.8L19.5 5.5 17.7 6.2 17 8l-.7-1.8L14.5 5.5l1.8-.7Z"/></svg>';
  }

  // 把节目正文渲染成 叙述卡片 + 台词气泡（主播用封面头像，嘉宾用固定头像）
  function _radioRenderSegments(raw, prog) {
    const segs = _parseRadioReply(raw);
    // 主播 = 正文里第一个开口说话的人（电台开场白一定是主播）；兜底用 prog.dj
    let djName = '';
    const firstLine = segs.find(s => s.kind !== 'desc' && s.speaker);
    if (firstLine) djName = firstLine.speaker;
    if (!djName) djName = (prog && prog.dj) || '';
    const coverImg = (prog && prog.cover) || '';
    let html = '';
    let segIdx = 0;
    for (const seg of segs) {
      if (!seg.text) continue;
      if (seg.kind === 'interact') {
        // 互动锚点：按玩法池渲染对应卡片（根据 state 显示不同状态）
        const play = _radioPlayById(seg.interact) || _RADIO_PLAYS.mail;
        const isDone = seg.state === 'done';
        const isSkip = seg.state === 'skip';
        const titleHtml = `${_radioPlaySvg(play.icon)}${Utils.escapeHtml(play.title)}`;
        let cardHtml = '';
        if (isDone) {
          cardHtml = `
            <div class="phone-radio-interact done" data-seg-idx="${segIdx}" data-interact="${Utils.escapeHtml(play.id)}">
              <div class="phone-radio-interact-title">${titleHtml}</div>
            <div class="phone-radio-interact-desc">${Utils.escapeHtml(play.descDone)}</div>
            </div>`;
        } else if (isSkip) {
          cardHtml = `
            <div class="phone-radio-interact skip" data-seg-idx="${segIdx}" data-interact="${Utils.escapeHtml(play.id)}">
              <div class="phone-radio-interact-title">${titleHtml}</div>
              <div class="phone-radio-interact-desc">${Utils.escapeHtml(play.descSkip)}</div>
            </div>`;
        } else {
          if (play.id === 'vote') {
            // 投票 pending：问题 + 选项按钮列表 + 不投票按钮。选项来自锚点参数 seg.params（首项为问题，其余为选项）
            const params = Array.isArray(seg.params) ? seg.params : [];
            const question = params[0] || '主播发起了一个投票';
            const options = params.slice(1);
            const optBtns = options.map((opt, oi) =>
              `<button class="phone-radio-vote-opt" type="button" data-act="vote" data-opt="${oi}">${Utils.escapeHtml(opt)}</button>`
            ).join('');
            cardHtml = `
              <div class="phone-radio-interact vote" data-seg-idx="${segIdx}" data-interact="${Utils.escapeHtml(play.id)}">
                <div class="phone-radio-interact-title">${titleHtml}</div>
                <div class="phone-radio-vote-q">${Utils.escapeHtml(question)}</div>
                <div class="phone-radio-vote-opts">${optBtns}</div>
                <div class="phone-radio-interact-actions">
                  <button class="phone-radio-interact-btn ghost" type="button" data-act="skip">${Utils.escapeHtml(play.skipLabel)}</button>
                </div>
              </div>`;
          } else {
            cardHtml = `
              <div class="phone-radio-interact" data-seg-idx="${segIdx}" data-interact="${Utils.escapeHtml(play.id)}">
                <div class="phone-radio-interact-title">${titleHtml}</div>
                <div class="phone-radio-interact-desc">${Utils.escapeHtml(play.descPending)}</div>
                <div class="phone-radio-interact-actions">
                  <button class="phone-radio-interact-btn ghost" type="button" data-act="skip">${Utils.escapeHtml(play.skipLabel)}</button>
                  <button class="phone-radio-interact-btn" type="button" data-act="play">${Utils.escapeHtml(play.actLabel)}</button>
                </div>
              </div>`;
          }
        }
        html += cardHtml;
      } else if (seg.kind === 'desc') {
        html += `<div class="phone-radio-narr" data-seg-idx="${segIdx}">${Utils.escapeHtml(seg.text)}</div>`;
      } else if (seg.kind === 'callme') {
        // 连线里玩家说的话：右对齐气泡（直显原文）
        html += `
          <div class="phone-radio-call-msg is-me" data-seg-idx="${segIdx}">
            <div class="phone-radio-call-bubble">${Utils.escapeHtml(seg.text)}</div>
          </div>`;
      } else if (seg.kind === 'caller') {
        // 来电听众（AI 虚构的打进热线的人）：右对齐、装饰色、电话听筒头像
        const callerName = seg.speaker || '听众';
        html += `
          <div class="phone-radio-line is-caller" data-seg-idx="${segIdx}">
            <div class="phone-radio-line-head">
              <div class="phone-radio-line-avatar"><div class="phone-radio-line-avatar-caller">${_radioCallerAvatar()}</div></div>
              <div class="phone-radio-line-name">${Utils.escapeHtml(callerName)}</div>
            </div>
            <div class="phone-radio-line-bubble">${Utils.escapeHtml(seg.text)}</div>
          </div>`;
      } else {
        // 判断说话人是主播还是嘉宾
        const isHost = !seg.speaker || seg.speaker === djName;
        const avatar = isHost
          ? (coverImg ? `<img src="${Utils.escapeHtml(coverImg)}" alt="">` : `<div class="phone-radio-line-avatar-fallback">${Utils.escapeHtml((djName || '主')[0])}</div>`)
          : `<div class="phone-radio-line-avatar-guest">${_radioGuestAvatar()}</div>`;
        const name = seg.speaker || djName || '主播';
        html += `
          <div class="phone-radio-line ${isHost ? 'is-host' : 'is-guest'}" data-seg-idx="${segIdx}">
            <div class="phone-radio-line-head">
              <div class="phone-radio-line-avatar">${avatar}</div>
              <div class="phone-radio-line-name">${Utils.escapeHtml(name)}</div>
            </div>
            <div class="phone-radio-line-bubble">${Utils.escapeHtml(seg.text)}</div>
          </div>`;
      }
      segIdx++;
    }
    return html;
  }

  // ===== 日历 App =====
let _calViewYear = 0, _calViewMonth = 0, _calSelectedDay = 0;

async function _renderCalendar(pd) {
  const body = document.getElementById('phone-body');
  document.getElementById('phone-title').textContent = '日历';
  _applyWallpaper(pd);

  // 异步刷新节日缓存
  await _refreshWvFestivalsCache();
  // 异步刷新历法规则缓存
  await _refreshCalRulesCache();

  // 读取当前游戏时间确定"今天"
  const sb = Conversations.getStatusBar() || {};
  const rules = _getCalRulesCached();
  const todayObj = (typeof Calendar !== 'undefined' && sb.time) ? Calendar.parseAbsoluteTime(sb.time) : null;

  // 初始化视图年月（第一次打开用"今天"，之后保持用户选择的）
  if (!_calViewYear) {
    _calViewYear = todayObj?.year || new Date().getFullYear();
    _calViewMonth = todayObj?.month || (new Date().getMonth() + 1);
    _calSelectedDay = todayObj?.day || new Date().getDate();
  }

  _renderCalBody(pd, rules, todayObj);
}

function _renderCalBody(pd, rules, todayObj) {
  const body = document.getElementById('phone-body');
  if (!body) return;

  const yr = _calViewYear, mo = _calViewMonth;
  const events = [...(pd?.calendarEvents || []), ..._getWvFestivalsAsEvents()];

  // 月份标题
  const monthsPerYear = rules?.monthsPerYear || 12;
  const prevMo = mo === 1 ? monthsPerYear : mo - 1;
  const prevYr = mo === 1 ? yr - 1 : yr;
  const nextMo = mo === monthsPerYear ? 1 : mo + 1;
  const nextYr = mo === monthsPerYear ? yr + 1 : yr;

  // 本月天数
  const daysInMonth = (rules && typeof Calendar !== 'undefined')
    ? Calendar._getDaysInMonth(mo, yr, rules)
    : new Date(yr, mo, 0).getDate();

  // 本月第一天的星期索引（0=第一天）
  const daysPerWeek = rules?.daysPerWeek || 7;
  let firstDayOffset = 0;
  if (rules && typeof Calendar !== 'undefined') {
    const firstDayEpoch = Calendar._daysSinceEpoch({ year: yr, month: mo, day: 1, hour: 0, minute: 0 }, rules);
    firstDayOffset = ((firstDayEpoch % daysPerWeek) + daysPerWeek) % daysPerWeek;
  } else {
    firstDayOffset = new Date(yr, mo - 1, 1).getDay();
    firstDayOffset = firstDayOffset === 0 ? 6 : firstDayOffset - 1; // 周一起始
  }

  // 星期表头
  const weekNames = rules?.weekDayNames || ['一','二','三','四','五','六','日'];
  const weekHeader = weekNames.map(n => `<div class="phone-cal-weekday">${Utils.escapeHtml(n.replace('星期',''))}</div>`).join('');
  const gridCols = `grid-template-columns:repeat(${daysPerWeek},1fr)`;

  // 有事件的日期 set（含持续天数范围）
  const eventDays = new Set();
  for (const ev of events) {
    let match = false;
    if (ev.repeat === 'monthly') {
      // 每月重复：任何月份都显示，只看日数
      match = true;
    } else if (ev.repeat === 'yearly') {
      // 每年重复：月匹配即可，不看年
      match = (ev.month === mo);
    } else {
      // 一次性：年月都要匹配
      match = (ev.month === mo && (!ev.year || ev.year === yr));
    }
    if (match) {
      const dur = Math.max(1, ev.duration || 1);
      for (let d = ev.day; d < ev.day + dur && d <= daysInMonth; d++) {
        eventDays.add(d);
      }
    }
  }

  // 日期格子
  let cells = '';
  // 空白占位
  for (let i = 0; i < firstDayOffset; i++) {
    cells += `<div class="phone-cal-cell phone-cal-cell-empty"></div>`;
  }
  for (let d = 1; d <= daysInMonth; d++) {
    const isToday = todayObj && todayObj.year === yr && todayObj.month === mo && todayObj.day === d;
    const isSel = _calSelectedDay === d;
    const hasDot = eventDays.has(d);
    cells += `<div class="phone-cal-cell${isToday ? ' phone-cal-today' : ''}${isSel ? ' phone-cal-selected' : ''}" onclick="Phone._calSelectDay(${yr},${mo},${d})">
      <span class="phone-cal-daynum">${d}</span>
      ${hasDot ? '<span class="phone-cal-dot"></span>' : ''}
    </div>`;
  }

  // 选中日的事项（含持续天数：ev.day ~ ev.day+duration-1 范围内的都显示）
  const selEvents = events.filter(ev => {
    let match = false;
    if (ev.repeat === 'monthly') {
      // 每月重复：任何月份，只看日数范围
      match = true;
    } else if (ev.repeat === 'yearly') {
      // 每年重复：月匹配即可
      if (ev.month !== mo) return false;
      match = true;
    } else {
      // 一次性：年月都要匹配
      if (ev.month !== mo || (ev.year && ev.year !== yr)) return false;
      match = true;
    }
    if (!match) return false;
    const dur = Math.max(1, ev.duration || 1);
    return _calSelectedDay >= ev.day && _calSelectedDay < ev.day + dur;
  });
  const evCards = selEvents.length
    ? selEvents.map(ev => {
        const svBtn = `viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"`;
        const editSvg = `<svg ${svBtn}><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>`;
        const delSvg  = `<svg ${svBtn}><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>`;
        const typeSvg = _calTypeIconOnly(ev.type);
        const metaParts = [_calTypeName(ev.type)];
        if (ev.note) metaParts.push(ev.note);
        if (ev.repeat === 'yearly') metaParts.push('每年');
        else if (ev.repeat === 'monthly') metaParts.push('每月');
        if (ev.duration && ev.duration > 1) metaParts.push(`${ev.duration}天`);
        const metaText = metaParts.join(' · ');
        return `
        <div class="phone-cal-ev-card">
          <div class="phone-cal-ev-dot" style="background:${ev.color || 'var(--accent)'}"></div>
          <div class="phone-cal-ev-body">
            <div class="phone-cal-ev-title">${Utils.escapeHtml(ev.title || '无标题')}${ev.fromWv ? '<span class="phone-cal-ev-wv-tag">世界观</span>' : ''}</div>
            <div class="phone-cal-ev-meta"><span class="phone-cal-ev-type-icon">${typeSvg}</span>${Utils.escapeHtml(metaText)}</div>
          </div>
          ${!ev.fromWv ? `<div class="phone-cal-ev-actions">
            <button class="phone-cal-ev-icon-btn" onclick="Phone._calOpenEditEvent('${Utils.escapeHtml(ev.id)}')" title="编辑">${editSvg}</button>
            <button class="phone-cal-ev-icon-btn phone-cal-ev-del-btn" onclick="Phone._calDeleteEvent('${Utils.escapeHtml(ev.id)}')" title="删除">${delSvg}</button>
          </div>` : ''}
        </div>`;
      }).join('')
    : `<div class="phone-cal-ev-empty">这一天没有事项</div>`;

  body.innerHTML = `
    <div class="phone-cal-wrap">
      <div class="phone-cal-header">
        <button class="phone-cal-nav-btn" onclick="Phone._calNavMonth(${prevYr},${prevMo})">‹</button>
        <span class="phone-cal-title-text">${yr}年 ${mo}月</span>
        <button class="phone-cal-nav-btn" onclick="Phone._calNavMonth(${nextYr},${nextMo})">›</button>
        <button class="phone-cal-today-btn" onclick="Phone._calGoToday()">今天</button>
      </div>
      <div class="phone-cal-grid-wrap">
        <div class="phone-cal-week-header" style="${gridCols}">${weekHeader}</div>
        <div class="phone-cal-grid" style="${gridCols}">${cells}</div>
      </div>
      <div class="phone-cal-day-panel">
        <div class="phone-cal-day-title">
          <span>${mo}月${_calSelectedDay}日</span>
          <button class="phone-cal-add-btn" onclick="Phone._calOpenAddEvent()">＋ 添加事项</button>
        </div>
        <div class="phone-cal-ev-list">${evCards}</div>
      </div>
    </div>`;
}

function _calTypeLabel(type) {
  const sv = `viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px;margin-right:3px"`;
  const icons = {
    birthday: `<svg ${sv}><path d="M20 21v-8a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v8"/><path d="M4 16s.5-1 2-1 2.5 2 4 2 2.5-2 4-2 2.5 2 4 2 2-1 2-1"/><line x1="2" y1="21" x2="22" y2="21"/><path d="M7 8v1M12 6v3M17 8v1"/></svg> 生日`,
    todo:     `<svg ${sv}><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg> 待办`,
    period:   `<svg ${sv}><path d="M12 22a7 7 0 0 0 7-7c0-2-1-3.9-3-5.5s-3.5-4-4-6.5c-.5 2.5-2 4.9-4 6.5C6 11.1 5 13 5 15a7 7 0 0 0 7 7z"/></svg> 经期`,
    holiday:  `<svg ${sv}><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg> 节日`,
    note:     `<svg ${sv}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg> 备忘`,
  };
  return icons[type] || `<svg ${sv}><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg> 事项`;
}

function _calTypeIconOnly(type) {
  const sv = `viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"`;
  const icons = {
    birthday: `<svg ${sv}><path d="M20 21v-8a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v8"/><path d="M4 16s.5-1 2-1 2.5 2 4 2 2.5-2 4-2 2.5 2 4 2 2-1 2-1"/><line x1="2" y1="21" x2="22" y2="21"/></svg>`,
    todo:     `<svg ${sv}><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>`,
    period:   `<svg ${sv}><path d="M12 22a7 7 0 0 0 7-7c0-2-1-3.9-3-5.5s-3.5-4-4-6.5c-.5 2.5-2 4.9-4 6.5C6 11.1 5 13 5 15a7 7 0 0 0 7 7z"/></svg>`,
    holiday:  `<svg ${sv}><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>`,
    note:     `<svg ${sv}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>`,
  };
  return icons[type] || `<svg ${sv}><circle cx="12" cy="10" r="3"/></svg>`;
}

function _calTypeName(type) {
  const map = { birthday: '生日', todo: '待办', period: '经期', holiday: '节日', note: '备忘' };
  return map[type] || '事项';
}

async function _calNavMonth(yr, mo) {
  _calViewYear = yr; _calViewMonth = mo; _calSelectedDay = 1;
  const pd = await _getPhoneData();
  const sb = Conversations.getStatusBar() || {};
  const rules = _getCalRulesCached();
  const todayObj = (typeof Calendar !== 'undefined' && sb.time) ? Calendar.parseAbsoluteTime(sb.time) : null;
  _renderCalBody(pd, rules, todayObj);
}

async function _calGoToday() {
  const sb = Conversations.getStatusBar() || {};
  const todayObj = (typeof Calendar !== 'undefined' && sb.time) ? Calendar.parseAbsoluteTime(sb.time) : null;
  _calViewYear = todayObj?.year || new Date().getFullYear();
  _calViewMonth = todayObj?.month || (new Date().getMonth() + 1);
  _calSelectedDay = todayObj?.day || new Date().getDate();
  const pd = await _getPhoneData();
  const rules = _getCalRulesCached();
  _renderCalBody(pd, rules, todayObj);
}

async function _calSelectDay(yr, mo, day) {
  _calViewYear = yr; _calViewMonth = mo; _calSelectedDay = day;
  const pd = await _getPhoneData();
  const sb = Conversations.getStatusBar() || {};
  const rules = _getCalRulesCached();
  const todayObj = (typeof Calendar !== 'undefined' && sb.time) ? Calendar.parseAbsoluteTime(sb.time) : null;
  _renderCalBody(pd, rules, todayObj);
}

function _calOpenAddEvent() {
  const yr = _calViewYear, mo = _calViewMonth, day = _calSelectedDay;
  const mask = document.createElement('div');
  mask.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.45);display:flex;align-items:flex-end;justify-content:center';
  mask.className = 'phone-cal-modal-mask';

  const sv = `viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"`;
  const types = [
    { id:'note',    label:'备忘', svg:`<svg ${sv}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>` },
    { id:'birthday',label:'生日', svg:`<svg ${sv}><path d="M20 21v-8a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v8"></path><path d="M4 16s.5-1 2-1 2.5 2 4 2 2.5-2 4-2 2.5 2 4 2 2-1 2-1"></path><line x1="2" y1="21" x2="22" y2="21"></line><path d="M7 8v2"></path><path d="M12 8v2"></path><path d="M17 8v2"></path><path d="M7 4 L 7 5"></path><path d="M12 3 L 12 5"></path><path d="M17 4 L 17 5"></path></svg>` },
    { id:'todo',    label:'待办', svg:`<svg ${sv}><polyline points="9 11 12 14 22 4"></polyline><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"></path></svg>` },
    { id:'period',  label:'经期', svg:`<svg ${sv}><path d="M12 22a7 7 0 0 0 7-7c0-2-1-3.9-3-5.5s-3.5-4-4-6.5c-.5 2.5-2 4.9-4 6.5C6 11.1 5 13 5 15a7 7 0 0 0 7 7z"></path></svg>` },
    { id:'holiday', label:'节日', svg:`<svg ${sv}><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon></svg>` },
  ];
  const typeGrid = types.map(t => `
    <div class="cal-type-chip" data-type="${t.id}" onclick="Phone._calPickType(this)" style="display:flex;flex-direction:column;align-items:center;gap:5px;padding:10px 6px;border-radius:12px;border:1.5px solid var(--border);cursor:pointer;flex:1;background:var(--bg-secondary);transition:all .15s;-webkit-tap-highlight-color:transparent">
      <span class="cal-type-icon" style="color:var(--text-secondary)">${t.svg}</span>
      <span style="font-size:11px;color:var(--text-secondary)">${t.label}</span>
    </div>`).join('');

  mask.innerHTML = `
    <div style="background:var(--bg);border-radius:20px 20px 0 0;padding:20px 16px 36px;width:100%;max-width:420px;max-height:80vh;overflow-y:auto">
      <div style="width:36px;height:4px;border-radius:2px;background:var(--border);margin:0 auto 18px"></div>
      <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:18px">${mo}月${day}日 · 添加事项</div>

      <div style="display:flex;flex-direction:column;gap:14px">

        <!-- 名称 -->
        <input id="cal-ev-title" type="text" placeholder="事项名称（必填）" maxlength="30"
          style="width:100%;padding:11px 14px;border-radius:12px;border:1.5px solid var(--border);background:var(--bg-secondary);color:var(--text);font-size:14px;box-sizing:border-box;outline:none">

        <!-- 类型 -->
        <div>
          <div style="font-size:12px;color:var(--text-secondary);margin-bottom:8px">类型</div>
          <div style="display:flex;gap:6px">${typeGrid}</div>
        </div>

        <!-- 颜色 + 备注 -->
        <div style="display:flex;gap:10px;align-items:center">
          <div style="font-size:12px;color:var(--text-secondary);white-space:nowrap">颜色</div>
          <div id="cal-ev-color-swatch"
            onclick="Phone._calOpenColorPicker(this)"
            data-color="#7c9ef0"
            style="width:32px;height:32px;border-radius:10px;background:#7c9ef0;cursor:pointer;flex-shrink:0;border:2px solid rgba(255,255,255,0.15);box-shadow:0 2px 6px rgba(0,0,0,0.18);transition:all .15s;-webkit-tap-highlight-color:transparent"></div>
          <input id="cal-ev-note" type="text" placeholder="备注（可选）" maxlength="60"
            style="flex:1;padding:11px 14px;border-radius:12px;border:1.5px solid var(--border);background:var(--bg-secondary);color:var(--text);font-size:14px;box-sizing:border-box;outline:none">
        </div>

        <!-- 重复 -->
        <div>
          <div style="font-size:12px;color:var(--text-secondary);margin-bottom:8px">重复</div>
          <div style="display:flex;gap:0;border-radius:12px;border:1.5px solid var(--border);overflow:hidden">
            <button id="cal-rep-once"    class="cal-rep-btn cal-rep-active" onclick="Phone._calPickRepeat('once')"    style="flex:1;padding:9px 0;border:none;font-size:13px;cursor:pointer;transition:all .15s;background:var(--accent);color:#fff;font-weight:600">不重复</button>
            <button id="cal-rep-monthly" class="cal-rep-btn"               onclick="Phone._calPickRepeat('monthly')" style="flex:1;padding:9px 0;border:none;font-size:13px;cursor:pointer;transition:all .15s;background:var(--bg-secondary);color:var(--text-secondary)">每月</button>
            <button id="cal-rep-yearly"  class="cal-rep-btn"               onclick="Phone._calPickRepeat('yearly')"  style="flex:1;padding:9px 0;border:none;font-size:13px;cursor:pointer;transition:all .15s;background:var(--bg-secondary);color:var(--text-secondary)">每年</button>
          </div>
        </div>

        <!-- 持续天数 -->
        <div style="display:flex;align-items:center;gap:10px">
          <div style="font-size:12px;color:var(--text-secondary);white-space:nowrap">持续天数</div>
          <input id="cal-ev-duration" type="number" min="1" max="365" value="1"
            style="width:72px;padding:9px 12px;border-radius:12px;border:1.5px solid var(--border);background:var(--bg-secondary);color:var(--text);font-size:14px;text-align:center;box-sizing:border-box;outline:none">
          <div style="font-size:12px;color:var(--text-secondary)">天（默认1天）</div>
        </div>

        <!-- 按钮 -->
        <div style="display:flex;gap:8px;margin-top:4px">
          <button onclick="this.closest('div[style*=fixed]').remove()"
            style="flex:1;padding:12px;border-radius:12px;border:1.5px solid var(--border);background:transparent;color:var(--text-secondary);font-size:14px;cursor:pointer">取消</button>
          <button onclick="Phone._calSaveEvent(${yr},${mo},${day})"
            style="flex:2;padding:12px;border-radius:12px;border:none;background:var(--accent);color:#fff;font-size:14px;font-weight:600;cursor:pointer">保存</button>
        </div>

      </div>
    </div>`;

  // 默认选中 note 类型
  mask.addEventListener('click', e => { if (e.target === mask) mask.remove(); });
  document.body.appendChild(mask);
  setTimeout(() => {
    const firstChip = mask.querySelector('.cal-type-chip[data-type="note"]');
    if (firstChip) Phone._calPickType(firstChip);
    document.getElementById('cal-ev-title')?.focus();
  }, 80);
}

// ===== 从世界观节日生成日历事项（只读，fromWv标记） =====
// 世界观/世界书节日缓存（异步刷新，同步读）
let _wvFestivalsCache = [];

// 异步刷新节日缓存（在打开日历APP时调用）
async function _refreshWvFestivalsCache() {
  try {
    const conv = Conversations.getList().find(c => c.id === Conversations.getCurrent());
    if (!conv) { _wvFestivalsCache = []; return; }

    // 1. 世界观节日（从对话绑定的世界观读DB）
    let allFestivals = [];
    const wvId = conv.worldviewId || conv.singleWorldviewId || '';
    let wv = null;
    if (wvId) {
      try { wv = await DB.get('worldviews', wvId); } catch(_) {}
    }
    if (wv?.festivals) allFestivals.push(...wv.festivals);

    // 2. 世界书节日
    try {
      if (typeof Lorebook !== 'undefined' && Lorebook.collectForChat) {
        let card = null;
        if (conv.isSingle && conv.singleCharType === 'card' && conv.singleCharId) {
          try { card = await DB.get('singleCards', conv.singleCharId); } catch(_) {}
        }
        const lbs = await Lorebook.collectForChat({ conv, card, wv });
        for (const lb of (lbs || [])) {
          if (Array.isArray(lb.festivals)) allFestivals.push(...lb.festivals);
        }
      }
    } catch(_) {}

    // 转成日历事项格式
    const result = [];
    for (const f of allFestivals) {
      if (f.enabled === false || !f.date) continue;
      const m1 = f.date.match(/(\d{4})[年\/\-.](\d{1,2})[月\/\-.](\d{1,2})/);
      const m2 = !m1 && f.date.match(/(\d{1,2})[月\/](\d{1,2})/);
      let month, day, year = 0;
      if (m1) { year = parseInt(m1[1]); month = parseInt(m1[2]); day = parseInt(m1[3]); }
      else if (m2) { month = parseInt(m2[1]); day = parseInt(m2[2]); }
      else continue;
      if (!month || !day) continue;
      result.push({
        id: f.id,
        title: f.name || '节日',
        type: 'holiday',
        color: '#e8a44a',
        note: f.content || '',
        year: f.yearly ? 0 : (year || 0),
        month, day,
        repeat: f.yearly ? 'yearly' : 'once',
        duration: 1,
        fromWv: true,
      });
    }
    _wvFestivalsCache = result;
  } catch(_) { _wvFestivalsCache = []; }
}

function _getWvFestivalsAsEvents() {
  return _wvFestivalsCache;
}

// 日历弹窗：调起色环
function _calOpenColorPicker(swatchEl) {
  if (typeof ColorPicker === 'undefined') return;
  const currentColor = swatchEl?.dataset.color || '#7c9ef0';
  ColorPicker.open(swatchEl, currentColor, 1, (hex) => {
    if (!hex) return;
    const el = document.getElementById('cal-ev-color-swatch');
    if (el) {
      el.dataset.color = hex;
      el.style.background = hex;
    }
  });
  // 色环 overlay 必须比弹窗 mask(99999) 更高
  requestAnimationFrame(() => {
    const ov = document.getElementById('cp-overlay');
    if (ov) ov.style.setProperty('z-index', '999999', 'important');
  });
}

// 日历弹窗：切换类型 chip
function _calPickType(el) {
  document.querySelectorAll('.cal-type-chip').forEach(c => {
    const isThis = c === el;
    c.dataset.selected = isThis ? '1' : '0';
    c.style.borderColor = isThis ? 'var(--accent)' : 'var(--border)';
    c.style.background = isThis ? 'color-mix(in srgb, var(--accent) 15%, var(--bg-secondary))' : 'var(--bg-secondary)';
    const icon = c.querySelector('.cal-type-icon');
    if (icon) icon.style.color = isThis ? 'var(--accent)' : 'var(--text-secondary)';
    const label = c.querySelector('span:last-child');
    if (label) label.style.color = isThis ? 'var(--accent)' : 'var(--text-secondary)';
  });
}

// 日历弹窗：切换重复选项
function _calPickRepeat(rep) {
  document.querySelectorAll('.cal-rep-btn').forEach(btn => {
    const isThis = btn.id === `cal-rep-${rep}`;
    btn.dataset.active = isThis ? '1' : '0';
    btn.dataset.rep = btn.id.replace('cal-rep-', '');
    btn.style.background = isThis ? 'var(--accent)' : 'var(--bg-secondary)';
    btn.style.color = isThis ? '#fff' : 'var(--text-secondary)';
    btn.style.fontWeight = isThis ? '600' : '400';
  });
}

async function _calSaveEvent(yr, mo, day) {
  const title = (document.getElementById('cal-ev-title')?.value || '').trim();
  if (!title) { UI.showToast('请填写事项名称', 1500); return; }
  // 从选中的 chip 读类型
  const activeChip = document.querySelector('.cal-type-chip[data-selected="1"]');
  const type = activeChip?.dataset.type || 'note';
  const color = document.getElementById('cal-ev-color-swatch')?.dataset.color || '#7c9ef0';
  const note = (document.getElementById('cal-ev-note')?.value || '').trim();
  // 从选中的重复按钮读重复方式
  const activeRep = document.querySelector('.cal-rep-btn[data-active="1"]');
  const repeat = activeRep?.dataset.rep || 'once';
  const duration = Math.max(1, parseInt(document.getElementById('cal-ev-duration')?.value || '1', 10) || 1);

  const pd = await _getPhoneData();
  if (!pd) return;
  pd.calendarEvents = pd.calendarEvents || [];
  pd.calendarEvents.push({
    id: Utils.uuid(),
    title, type, color, note,
    year: (repeat === 'yearly' || repeat === 'monthly') ? 0 : yr,
    month: mo, day,
    repeat: repeat || 'once',
    duration: duration,
    createdAt: Date.now()
  });
  await _savePhoneData();

  // 关闭弹窗
  document.querySelector('.phone-cal-modal-mask')?.remove();

  // 刷新视图
  const sb = Conversations.getStatusBar() || {};
  const rules = _getCalRulesCached();
  const todayObj = (typeof Calendar !== 'undefined' && sb.time) ? Calendar.parseAbsoluteTime(sb.time) : null;
  _renderCalBody(pd, rules, todayObj);
  _refreshCalBanner();
  UI.showToast('已添加', 1200);
}

